// ==UserScript==
// @name         无限流-副本生成器
// @namespace    http://tampermonkey.net/
// @version      2.0.2
// @description  无限流副本世界生成器
// @author       Gloria
// @match        *://*/*
// @grant        none
// ==/UserScript==

(function () {
  'use strict';

  console.log('DUNGEON_GEN: Script execution started.');

  // ─────────────────────────────────────────
  // 常量
  // ─────────────────────────────────────────
  const SCRIPT_ID      = 'dungeonGenerator';
  const POPUP_ID       = `${SCRIPT_ID}-popup`;
  const MENU_ID        = `${SCRIPT_ID}-menu-item`;
  const SHELL_ID       = `${SCRIPT_ID}-shell`;
  const _SHELL_STYLE_ID = `${SCRIPT_ID}-shell-css`;
  const WORLDBOOK_NAME = '_我的无限流不是智障';

  const STORAGE_KEY_API     = `${SCRIPT_ID}_apiConfig_v1`;
  const STORAGE_KEY_PROMPT  = `${SCRIPT_ID}_prompt_v2`;
  const STORAGE_KEY_THEME   = `${SCRIPT_ID}_theme_v1`;
  const STORAGE_KEY_PRESETS = `${SCRIPT_ID}_presets_v1`;
  const STORAGE_KEY_PERSONA        = `${SCRIPT_ID}_persona_v1`;
  const STORAGE_KEY_CUSTOM_THEMES  = `${SCRIPT_ID}_customThemes_v1`;
  const STORAGE_KEY_CUSTOM_RATINGS = `${SCRIPT_ID}_customRatings_v1`;
  const STORAGE_KEY_INJECTION_PRESETS = `${SCRIPT_ID}_injectionPresets_v1`;
  const STORAGE_KEY_PROMPT_PRESETS    = `${SCRIPT_ID}_promptPresets_v1`;
  const STORAGE_KEY_GEN_PRESETS       = `${SCRIPT_ID}_genPresets_v1`;
  const STORAGE_KEY_SUMMARIES         = `${SCRIPT_ID}_summaries_v1`;
  const STORAGE_KEY_SUMMARY_REQ       = `${SCRIPT_ID}_summaryReq_v1`;
  const STORAGE_KEY_DELETED_THEMES    = `${SCRIPT_ID}_deletedThemes_v1`;
  const STORAGE_KEY_DELETED_RATINGS   = `${SCRIPT_ID}_deletedRatings_v1`;

  const THEMES = [
    '日式怨灵', '克苏鲁宇宙', '生存恐怖', '社会实验', '游戏化副本',
    '民俗宗教', '时间循环', '科幻异变', '隐藏身份', '中式民俗',
    '童话异变', '末日废土', '密室解谜', '战争遗留', '海洋深渊',
    '镜像替换', '表演困境', '神明降临', '数字幽灵', '童年创伤',
    '异星接触'
  ];
  const RATINGS = ['E','D','C','B','A','S','SSS'];

  const MENU_SELECTORS = [
    '#extensionsMenu',
    '#extensionMenuItems',
    '.extensions_block',
    '#extension_settings',
    '#extensionsMenuList',
    '.extension_menu',
    '#rm_extensions_block',
  ];

  const DEFAULT_PROMPT = `# 任务
你是一名专业的无限流副本设计师，擅长中国网络文学风格的沉浸式世界构建。
目标：根据用户填入的副本参数，严格遵循MODULE 2的约束规则，生成一个逻辑自洽、张力饱满、高自由度的副本完整世界观框架。输出应精炼、信息密度高、可直接供创作使用。

# 输出Goal
- 玩家一律用'{{user}}'代替。
- 格式：严格纯文本，禁止使用 *、**、#、表格或分割线。
- 结构：使用 [章节名] 区分模块，条目采用 - 开头。
- 极简主义：删除所有修饰性词汇，仅保留核心逻辑与关键词，追求极致的信息密度。
- 输出结构完整的副本世界观（非故事，是可供发挥的"舞台"）
- 机制与世界观深度绑定，非装饰性
- 埋设足够的反转点与张力来源，但不提前触发
- 严格遵循 MODULE 2 的评级与人数约束：低评级不强行塞入高难度机制，高评级不保留安全逃脱口

---

# MODULE 0 · 副本信息填入
{{MODULE_0_BLOCK}}

---


# MODULE1 · 参考框架库

## 参考无限流作品（内化，不直接引用）
杀戮副本系 | 鬼打墙、无限恐怖、我在异界有座城、诡秘之主
游戏化副本系 | 全球高考、副本攻略、无限之任务系统、我的玩家都是演技派
社会实验系 | 请回答1988·异变版、末日游乐场、开局一座山
恐怖解谜系 | 异常现象记录员、诡异复苏、让我们猜猜我是谁
竞争淘汰系 | 我不是反派、鱿鱼游戏式无限流、末日拍卖行
隐藏身份系 | 狼人杀型、卧底入侵型、身份替换型
循环机制系 | 时间循环副本、存档重置型、死亡倒放型

## 完美副本（内化）
- 信息不对称 | 玩家初始信息必须残缺，真相需付出代价获取
- 规则悖论 | 至少一条规则存在例外或陷阱
- 资源压迫 | 时间/体力/道具三者不可同时充裕
- 人性压力 | 机制设计需逼出背叛或牺牲的可能性
- 层叠真相 | 表象/中层/核心真相各不相同
- Boss人格化 | Boss有动机、有弱点、有可对话空间
- 环境叙事 | 场景本身携带世界观信息，不依赖说教
- 出口成本 | 通关条件必须让玩家付出某种不可逆代价

## 副本类型库（类型 | 核心美学 | 怪物逻辑 | 标志元素）
日式怨灵 | 执念/因果/无声压迫 | 还原死因才能破局，不可正面对抗 | 黑发/镜子/水面/缓慢移动/温度骤降/死亡原因调查
克苏鲁宇宙 | 渺小/理性崩溃/不可名状 | 直视发疯，规则在此无效 | 错误几何/语言失效/理智值/越知道越危险
生存恐怖 | 资源匮乏/身体威胁/安全剥夺 | 有实体有弱点，但资源永远不够 | 弹药计数/噪音管理/安全屋/物资争夺道德题
社会实验 | 人性黑暗/规则即陷阱 | 人本身是怪物，设计者是终极BOSS | 投票/信息不对称/背叛/联盟瓦解/利益分配
游戏化副本 | 元叙事/规则即世界 | 违反游戏规则的存在/游戏本身是陷阱 | UI植入现实/任务提示双关/隐藏条件/规则漏洞
民俗宗教 | 仪式/禁忌/共同体压迫 | 神明确实存在，外来者是异物 | 笑脸恐怖/集体疯狂/地方方言/节日仪式/必须假装融入
时间循环 | 宿命/信息积累/存在性绝望 | 循环本身是陷阱，每次重置不完全 | 细节微变/NPC行为偏移/自己的尸体/死亡信息拼凑破局
科幻异变 | 技术失控/边界崩溃/身体异化 | 符合科学但已超出控制 | 感染扩散/改造身体/AI叛乱/谁已被感染
隐藏身份 | 不信任/表演/信息博弈 | 混在人群中，有微小破绽 | 投票淘汰/行为反常细节/错杀代价/替换整个群体
中式民俗 | 阴阳秩序/禁忌繁多/因果轮回 | 怨鬼执念明确，必须以礼法/仪式应对 | 红盖头/纸人/牌位/符咒/阴婚/傩戏面具/蛊/赶尸/黄皮子/出马仙
童话异变 | 熟悉感错位/纯真表象下的残酷 | 规则来自童话原典，违反即触发惩罚 | 王子公主角色固定/善恶判定机制/结局必须圆满否则循环/森林/城堡/魔法道具有代价
末日废土 | 秩序崩溃/物资即权力/人性极限 | 人与变异体并存，最大威胁是其他幸存者| 势力割据/以物易物/辐射/变异动植物/废弃军事设施/道德底线磨损
密室解谜 | 智识对抗/空间压迫/时钟倒计时 | 房间本身是怪物，机关是它的意志 | 隐藏夹层/机关连锁/错误密码触发惩罚/出口是另一个密室/设计者遗留的执念
战争遗留 | 历史创伤/幽灵战场/无法结束的战争 | 亡者不知自己已死，仍在执行任务 | 壕沟/废弃军营/无线电信号/满是弹孔的建筑/敌我识别危机/战争罪行的回响
海洋深渊 | 压迫感/黑暗/不可探知的深度 | 深海生物遵循捕食本能，光是诱饵也是武器 | 潜水艇/沉船/氧气倒计时/发光诱饵/声呐异常/水压/深海禁区坐标
镜像替换 | 自我认同崩溃/真实性存疑 | 替换体比原版更「正确」，原版被视为异常 | 细节偏差/家人不认识你/证件消失/另一个自己已在生活/镜子是入口
表演困境 | 戏中戏/角色与自我的边界消融 | 剧本即诅咒，演完即成真，出戏即死亡 | 剧场/剧本页数倒计时/角色死亡影响玩家/观众席坐着不该在的人/台词暗语
神明降临 | 信仰异化/神迹与恐怖的一体两面 | 神明确实降临且全知，但其善意本身是灾难 | 神谕/祭品/奇迹附带代价/信徒狂热/异端审判/神明的逻辑与人类价值观根本相悖
数字幽灵 | 现实与数据的边界瓦解/存在性恐惧 | 存在于数字空间中的意识，通过设备渗透现实 | 屏幕异常/删除的文件复活/死者账号发消息/监控视角/代码中的求救信息/断网即死
童年创伤 | 记忆重构/无法抵达的过去/成人视角的失效 | 以儿童逻辑运作，成年人的理性在此是弱点 | 过时玩具/废弃幼儿园/儿歌/画作预言/儿童视角见到的才是真相/大人看不见的存在
异星接触 | 认知框架不兼容/沟通即危险 | 外星存在无善恶之分，人类对它而言是样本 | 信号破译/身体扫描/实验舱/被研究的感觉/同伴逐渐被同化/语言无法传达的概念

## 场景库（场景 | 恐怖设计示例 | 标志细节）
封闭建筑 | 酒店/医院/学校/地下室/游轮 | 不存在的楼层/放学后教室/精神病院地下/密闭无退路
开放异变 | 古村/废城/森林/游乐园 | 地图有隐形边界/树木重复/方向失效/欢乐表象下的恐怖
虚实叠加 | 镜中世界/梦境/记忆宫殿/数字空间 | 镜中自我有独立意志/逻辑不连贯是常态/记忆被篡改/像素化边缘

## 规则库（规则类型 | 功能 | 设计原则）
明规则 | 公开告知，建立基础安全感 | 必须违反才能通关，或遵守到底才能通关，二选一
暗规则 | 观察推断，NPC行为/道具用法 | 怪物真实弱点往往与明规则所述不同
伪规则 | 陷阱，看起来像规则实则致死 | 遵守它安全但错过通关条件
悖论规则| 遵守A必然违反B，高压张力核心 | 救人=暴露位置/知道真相=成为被清除目标

禁止类 | 禁止照镜子/说某名字/奔跑/对视/独处/睡觉/打开XX门
必须类 | 必须定时出现在某处/完成仪式/保持某种行为（微笑/沉默/直视前方）
条件类 | 「如果看到X立即做Y」/「当Z发生时不要Z」/「还有人活着怪物就不进入」

## 怪物库（类型 | 感知方式 | 弱点逻辑）
声音感知型 | 静止可规避，任何噪音触发追击 | 绝对安静/隔音屏障
视线感知型 | 注视时静止，转身时移动（盲目天使） | 永不转身/多人持续注视
规则绑定型 | 自身也受规则约束，规则来自执念或仪式 | 执念反向即弱点，但使用有道德代价
模仿替换型 | 复制已死玩家声音/面容，细节有微小偏差 | 找到破绽/不给接触机会
智能型 | 会学习/设陷阱/针对个人弱点，可沟通但是陷阱| 比玩家更了解副本规则
被动存在型 | 单纯存在即致命，触碰/直视/命名即激活 | 绕过而非对抗
潜伏伪装型  | 以玩家身份混入队伍，静待时机 | 暴露时机往往是队伍最脆弱处

形态标志 | 关节方向错误/皮肤纹理异常/比例失调/无眼或满是眼睛/边界模糊与阴影融合
声音标志 | 人声+低频哼鸣叠加/只会重复一句话/倒着说话/声音从错误位置发出

## NPC库（类型 | 表面功能 | 暗层 | 张力设计）
引导型 | 提供信息/指路/规则讲解 | 信息不完整或故意错误，自身也是受害者 | 必须依赖但不能完全信任
同伴型 | 并肩作战，有情感连接 | 隐藏议程/可能是卧底或已感染 | 牺牲有利通关，救援有利情感线
受害者型| 展示规则后果，提供线索 | 死法本身传递信息，暗示通关路径 | 死亡不能是无意义的
守门人型| 掌握关键资源/信息/通道 | 必须以特定方式打交道（贿赂/欺骗/满足执念）| 盟友or障碍取决于玩家选择
异常型 | 行为不符任何已知模式 | 怪物伪装/管理者/前代玩家残影/真正BOSS | 最后一刻才揭示真实身份

## 副本速构清单
五问 | 核心异常是什么 / 通关条件表面vs真实是什么 / 玩家最依赖什么（然后摧毁它）/ 第一个被植入的错误认知是什么 / 最好和最坏结局分别是什么
必要元素 | 明确的地图边界 / 三条规则（陷阱+有用+需违反才通关）/ 一个不可正面对抗的威胁 / 两个目的相互冲突的NPC / 一个核心谜题（解开后改变对副本的全部认知）/ 一次无完美选项的道德困境 / 一个已死的重要角色持续影响副本 / 至少三个结局分支（由积累选择决定，而非单一最终选择）

---

MODULE 2 · 参数引导手册

### 评级约束
| 评级 | 副本时长 | 预期死亡率 | 世界层数/真相深度 | 生存机制 | Boss | 隐藏规则 | 整体基调 |
| E | 短（几小时内） | <5% | 表层即全部，无真相层 | 仅主机制，规则直白 | 无/象征性 | 不设 | 教学副本，队友新人居多，建立恐惧感即可 |
| D | 短～中 | 5~20% | 轻微表层/真相落差 | 主机制+简单资源限制 | 可选，单阶段 | 1~2，多为NPC身份 | 初级悬疑，死亡偶发 |
| C | 中 | 20~40% | 明确双层结构，真相中期可推断 | 主+辅助机制二选一 | 单阶段，有触发条件 | 可选1个，双向用途 | 信息不对称开始显现 |
| B | 中～长 | 40~60% | 双层结构完整，真相终局前揭晓 | 主+辅助+隐藏规则 | 2阶段，有情感钩子 | 必须1个 | 高压、欺骗、队友存疑 |
| A | 长 | 60~80% | 三层结构（表层/逻辑层/根源真相） | 多机制联动，存在机制冲突 | 2~3阶段，机制与玩家行为挂钩 | 2个，至少1个可被利用作陷阱 | 道德困境，解法无纯净答案 |
| S | 长，时间本身可能是机制 | 80~95% | 世界逻辑自洽但根基崩塌，真相颠覆玩法认知 | 机制存在内在矛盾或自我演化 | 多阶段，Boss可能非实体或即玩家 | 多个，部分规则本身是谎言 | 存在主义恐惧，没有安全解 |
| SSS | 极长或时间感扭曲 | >95% | 世界层数无法完全厘清，真相开放性或不可知 | 规则随进度变异，玩家行为改写机制 | Boss即副本本身或系统层实体 | 规则边界模糊，发现隐藏规则本身有代价 | 末日级，通关定义本身存疑 |

### 人数约束
| 队伍人数 | 队伍信息密度 | 内鬼设置 | 信息分配方式 | 场景设计倾向 | 死亡规则影响 | 氛围关键词 |
| 1（单人） | 填"单人副本" | 无（可设"内化内鬼"：记忆/精神分裂） | 线性发现，全部信息归玩家 | 密闭、循环、镜像空间 | 死亡即失败，无容错 | 孤立、自我怀疑、绝望 |
| 2~3 | 功能互补 | 内鬼概率低，设则剧情冲击大 | 信息碎片分散，需交流拼图 | 分支路线，可分离设计 | 队友死亡触发格局重构 | 信任博弈、依赖与背叛 |
| 4~6 | 含1个功能模糊角色 | 可设1名内鬼（主动/被动均可） | 关键信息定向分配，形成信息差 | 多功能区并行，需分工 | 死亡改变存活资源/规则平衡 | 派系分化、怀疑蔓延 |
| 7~10 | 仅填关键角色 | 可设1~2名内鬼，建议类型不同 | 信息碎片化且存在虚假信息 | 大型地图，子场景分散 | 死亡可作为信息来源（遗物/遗言） | 社会动力学、集体恐慌 |
| 10+ | 仅填关键角色| 内鬼比例可提升，洗脑型更适合 | 信息可公开伪造，存在舆论操控机制 | 可设"区域控制"或阵营占点 | 死亡常态化，需设群体心理机制 | 权力结构、乌合之众、清洗 |

### 竞争模式约束
| 模式 | 核心玩法导向 | NPC设计重心 | Boss角色 | 道具设计倾向 | 禁止/不推荐 |
| PVE | 玩家协作解谜/生存（但内鬼仍可存在） | NPC是信息源与情感锚点，友好NPC有隐瞒 | 主要冲突焦点，机制完整 | 功能型为主，有合作使用场景 | 强行设置队伍对立，否则破坏协作逻辑 |
| PVP | 玩家间竞争/淘汰为核心，副本是舞台 | NPC作为资源/工具/立场倾斜变量 | Boss可弱化或作为"清场机制"而非焦点 | 稀缺资源型、零和竞争型，道具争夺触发冲突 | 设置强合作必要机制（与PVP冲突） |
