  async function getLastChatMessage() {
    try {
      if (TH && typeof TH.getLastMessageId === 'function' && typeof TH.getChatMessages === 'function') {
        const lastId = TH.getLastMessageId();
        log('getLastChatMessage: lastId =', lastId);
        if (lastId >= 0) {
          let msgs = await TH.getChatMessages(lastId, { include_swipes: false }).catch(() => null);
          if (!msgs || !msgs.length) {
            msgs = await TH.getChatMessages(`${lastId}-${lastId}`, { include_swipes: false }).catch(() => null);
          }
          if (msgs && msgs.length > 0) {
            const text = msgs[0].message || msgs[0].mes || '';
            if (text) { log('getLastChatMessage: got via TH, len=', text.length); return text; }
          }
        }
      }
    } catch(e) { warn('getLastChatMessage TH path failed:', e); }

    try {
      const pw = (window !== window.parent) ? window.parent : window;
      const gGetLast = pw.getLastMessageId || (typeof getLastMessageId !== 'undefined' ? getLastMessageId : null);
      const gGetMsgs = pw.getChatMessages  || (typeof getChatMessages  !== 'undefined' ? getChatMessages  : null);
      if (gGetLast && gGetMsgs) {
        const lastId = gGetLast();
        if (lastId >= 0) {
          const msgs = gGetMsgs(lastId);
          const text = msgs?.[0]?.message || msgs?.[0]?.mes || '';
          if (text) { log('getLastChatMessage: got via global fn, len=', text.length); return text; }
        }
      }
    } catch(e) { warn('getLastChatMessage global fn path failed:', e); }

    try {
      const ctx = ST && ST.getContext ? ST.getContext() : null;
      if (ctx && Array.isArray(ctx.chat) && ctx.chat.length > 0) {
        const last = ctx.chat[ctx.chat.length - 1];
        const text = last.mes || last.message || '';
        if (text) { log('getLastChatMessage: got via ctx.chat, len=', text.length); return text; }
      }
    } catch(e) { warn('getLastChatMessage ctx.chat path failed:', e); }

    try {
      const pw = (window !== window.parent) ? window.parent : window;
      const subMacros = pw.substitudeMacros || (typeof substitudeMacros !== 'undefined' ? substitudeMacros : null);
      if (subMacros) {
        const text = subMacros('{{lastMessage}}');
        if (text && text !== '{{lastMessage}}') {
          log('getLastChatMessage: got via substitudeMacros, len=', text.length);
          return text;
        }
      }
    } catch(e) { warn('getLastChatMessage substitudeMacros path failed:', e); }

    warn('getLastChatMessage: all paths failed');
    return '';
  }

