    if (!ok) return false;

    const now     = new Date();
    const dateStr = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;
    const entryTitle = `${rating || '?'}-${name || '副本'}-${dateStr}`;

    const entry = {
      comment: entryTitle,
      content: dungeonContent || '',
      enabled: true,
      type: 'constant',
      position: 'before_character_definition',
      depth: 998,
      order: 998,
      probability: 100,
      key: [],
      logic: 'and_any',
    };

    try {
      const r = await TH.createLorebookEntries(WORLDBOOK_NAME, [entry]);
      if (r && r.new_uids && r.new_uids.length > 0) {
        toast('success', `副本 "${entryTitle}" 已注入世界书 (depth 998)`);
        return true;
      }
      throw new Error('createLorebookEntries 返回空');
    } catch(e) {
      err('injectToWorldbook primary failed:', e);
      try {
        const all = await TH.getLorebookEntries(WORLDBOOK_NAME);
        if (TH && typeof TH.replaceWorldbook === 'function') {
          const tmp = { ...entry, uid: 'dg_' + Date.now() + '_' + Math.random().toString(36).slice(2,7) };
          await TH.replaceWorldbook(WORLDBOOK_NAME, [...(all || []), tmp]);
          toast('success', `副本 "${entryTitle}" 已注入（备用方案）`);
          return true;
        }
      } catch(e2) { err('fallback inject failed:', e2); }
      toast('error', `注入世界书失败: ${e.message}`);
      return false;
    }
  }

  // ─────────────────────────────────────────
  // AI 调用
  // ─────────────────────────────────────────
  async function callAI(prompt) {
    if (!apiConfig.url || !apiConfig.model) throw new Error('请先配置自定义API');
    let url = apiConfig.url.trim();
    if (!url.endsWith('/')) url += '/';
    if (!url.includes('v1/')) url += 'v1/';
    url += 'chat/completions';
    const headers = { 'Content-Type': 'application/json' };
    if (apiConfig.apiKey) headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
    const res = await fetch(url, {
      method: 'POST', headers,
      body: JSON.stringify({ model: apiConfig.model, messages: [{ role:'user', content: prompt }], temperature: 1, max_tokens: 4096 }),
    });
    if (!res.ok) { const t = await res.text(); throw new Error(`API错误 ${res.status}: ${t.slice(0,200)}`); }
    const data = await res.json();
    if (data.choices?.[0]?.message?.content) return data.choices[0].message.content.trim();
    throw new Error('API响应格式异常');
  }


  async function waitForAIResponse(timeout = 90000) {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error('等待AI响应超时')), timeout);
      const pw = (window !== window.parent) ? window.parent : window;
      const evOnce = pw.eventOnce || (typeof eventOnce !== 'undefined' ? eventOnce : null);
      const evts   = pw.tavern_events || (typeof tavern_events !== 'undefined' ? tavern_events : null);
      if (!evOnce || !evts) {
        clearTimeout(timer);
        reject(new Error('eventOnce/tavern_events 不可用，请使用自定义API'));
        return;
      }
      evOnce(evts.MESSAGE_RECEIVED, async (msgId) => {
        clearTimeout(timer);
        try {
          const msgs = TH.getChatMessages ? await TH.getChatMessages(msgId) : [];
          resolve(msgs && msgs.length ? msgs[0].message || '' : '');
        } catch(e) { reject(e); }
      });
    });
  }

  // ─────────────────────────────────────────
  // 解析响应
  // ─────────────────────────────────────────
  function parseResponse(text) {
    const infoM    = text.match(/<dungeon_info>([\s\S]*?)<\/dungeon_info>/);
    const dungeonM = text.match(/<dungeon>([\s\S]*?)<\/dungeon>/);
    return { info: infoM ? infoM[1].trim() : '', full: dungeonM ? dungeonM[1].trim() : text, raw: text };
  }
  function parseDungeonInfo(infoText) {
    const get = (key) => { const m = infoText.match(new RegExp(`${key}：([^\\n]+)`)); return m ? m[1].trim() : ''; };
    return { name: get('副本名称'), themes: get('副本主题'), rating: get('评级'), players: get('人数'), opening: get('开场') };
  }

  // ─────────────────────────────────────────
  // 构建 Prompt
  // ─────────────────────────────────────────
  async function buildPrompt(cfg) {
    const $p = getPopup();

    const themesStr  = (cfg.themes.includes('全选')  || !cfg.themes.length)  ? '随机' : cfg.themes.join('、');
    const ratingsStr = (cfg.ratings.includes('全选') || !cfg.ratings.length) ? '随机' : cfg.ratings.join('/');
    const playersStr = cfg.players.trim() || '随机';
    const specialStr = cfg.special || '无';
    const userSpecialStr = cfg.userSpecialEnabled
      ? '是'
      : '否';
    const userSpecialExtra = cfg.userSpecialEnabled
      ? `\n{{user}}的身份：${cfg.userIdentity}`
        + (cfg.userIdentityDesc ? `\n{{user}}身份的详细描述：${cfg.userIdentityDesc}` : '')
      : '';

    const configBlock =
`以下是副本配置信息：
副本名称：${cfg.name || '（随机）'}
副本主题：${themesStr}
评级：${ratingsStr}
人数：${playersStr}
竞争模式：${cfg.mode}
用户特殊设定：${userSpecialStr}${userSpecialExtra}
特殊要求：${specialStr}
参与者姓名：${cfg.teammates}
语言：${cfg.lang}
读取设定：${cfg.readContext}`;

    const isFusion = cfg.readContext === '是';

    let wbText = '无';
    if (isFusion && $p) {
      const sel = [];
      $p.find('#dg-lorebook-list .dg-tag-btn.active').each(function () {
        const e = $j(this).data('entry');
        if (e && e.content) sel.push(`[${e.label}]\n${e.content}`);
      });
      if (sel.length) wbText = sel.join('\n\n');
    }

    let personaText = '无', charDescText = '无';
    if (isFusion) {
      try {
        const ctx = ST && ST.getContext ? ST.getContext() : null;
        if ($p) {
          if ($p.find('#chk-persona').is(':checked')) {
            if (customPersonaText && customPersonaText.trim()) {
              personaText = customPersonaText.trim();
            } else if (ctx) {
              personaText = ctx.personaDescription || ctx.persona || ctx.user_desc || '无';
            }
          }
          if ($p.find('#chk-char-desc').is(':checked') && ctx) {
            const char = ctx.characters && ctx.characterId >= 0 ? ctx.characters[ctx.characterId] : null;
            const charData = char?.data || char || {};
            charDescText = ctx.description || charData.description || '无';
          }
        }
      } catch(e) { warn('读取ST上下文失败:', e); }
    }

    log(`buildPrompt: isFusion=${isFusion}, wbText长度=${wbText.length}, persona=${personaText!=='无'}, charDesc=${charDescText!=='无'}, customPersona=${!!customPersonaText.trim()}`);

    let chatBlock = '';
    if (cfg.injectChat && isFusion) {
      const lastMsg = await getLastChatMessage();
      if (lastMsg && lastMsg.trim()) {
        chatBlock = `\n【以下为最新剧情内容，请根据剧情内容自动提取副本相关信息，生成匹配的副本】\n${lastMsg.trim()}`;
        log('chatBlock injected, length:', lastMsg.length);
      } else {
        chatBlock = '\n（注入聊天记录：当前聊天为空或未获取到内容）';
        warn('chatBlock: no message found');
      }
    }

    const contextSection = isFusion
      ? `\n【以下是世界观设定】\n${wbText}\n【以下是{{user}}的基本信息】\n${personaText}\n【以下是角色信息】\n${charDescText}`
      : '';

    const summaryInjectId = $p ? $p.find('#dg-summary-inject-select').val() : '';
    const injectedSummary = summaryInjectId ? summaries.find(s => s.id === summaryInjectId) : null;
    const summaryBlock    = injectedSummary
      ? `\n【以下是{{user}}的当前主线剧情】：\n${injectedSummary.content}`
      : '';
    const module0Block = `${configBlock}${contextSection}${summaryBlock}${chatBlock}`;

    if (currentPrompt.includes('{{MODULE_0_BLOCK}}')) {
      return currentPrompt.replace('{{MODULE_0_BLOCK}}', module0Block);
    }
    return currentPrompt
      .replace('{{副本名称}}',  cfg.name || '（随机）')
      .replace('{{副本主题}}',  themesStr)
      .replace('{{评级}}',      ratingsStr)
      .replace('{{人数}}',      playersStr)
      .replace('{{竞争模式}}',  cfg.mode)
      .replace('{{特殊要求}}',  specialStr)
      .replace('{{队友姓名}}',  cfg.teammates)
      .replace('{{语言}}',      cfg.lang)
      .replace('{{读取设定}}',  cfg.readContext)
      .replace('{{附加设定}}',  isFusion ? `\n${wbText}\n${personaText}\n${charDescText}` : '')
      .replace('{{聊天记录}}',  chatBlock);
  }

  // ─────────────────────────────────────────
