  // ─────────────────────────────────────────
  // 菜单项
  // ─────────────────────────────────────────
  // 宿主 frame 访问辅助（酒馆助手 srcdoc iframe → 宿主 window/document/jQuery）
  // ─────────────────────────────────────────
  function getHostWindow() {
    try { return (window.parent && window.parent !== window) ? window.parent : window; }
    catch(e) { return window; }
  }
  function getHostDocument() {
    try { const w = getHostWindow(); return w.document || document; }
    catch(e) { return document; }
  }
  function getHostJQ() {
    try { const w = getHostWindow(); return w.$ || w.jQuery || $j; }
    catch(e) { return $j; }
  }

  // ─────────────────────────────────────────
  function _getHostTargets() {
    // 返回 [{ doc, jq }] 数组，优先尝试宿主 frame
    const targets = [];
    try {
      if (window.parent && window.parent !== window) {
        // 测试跨域可访问性，跨域时抛出 SecurityError
        void window.parent.document.body;
        const parentJQ = window.parent.$ || window.parent.jQuery || $j;
        targets.push({ doc: window.parent.document, jq: parentJQ });
      }
    } catch(e) {
      // 跨域，静默跳过 parent
    }
    targets.push({ doc: document, jq: $j });
    return targets;
  }

  // 外部重试计数器（独立于函数对象，每次从 init/addMenuItem 主入口调用时重置）
  let _menuRetries = 0;
  let _menuRetryTimer = null;

  function addMenuItem() {
    // 清除上一轮残留的重试定时器（防止并发）
    if (_menuRetryTimer) { clearTimeout(_menuRetryTimer); _menuRetryTimer = null; }
    _menuRetries = 0;
    _tryInjectMenu();
  }

  function _tryInjectMenu() {
    const targets = _getHostTargets();

    for (const { doc: pd, jq: pj } of targets) {
      if (!pd || !pj) continue;
      if (pj(`#${MENU_ID}`, pd).length) {
        // 已注入，确保观察器在运行
        _installMenuObserver(pd, pj);
        return;
      }

      let menu = null;
      for (const sel of MENU_SELECTORS) {
        const found = pj(sel, pd);
        if (found.length) { menu = found; log(`菜单容器命中: ${sel}`); break; }
      }

      if (menu) {
        _appendMenuItem(menu, pd, pj);
        _installMenuObserver(pd, pj);
        return;
      }
    }

    // 未找到容器，继续重试
    _menuRetries++;
    if (_menuRetries < 30) {
      const delay = _menuRetries < 5 ? 1000 : _menuRetries < 15 ? 2000 : 3000;
      log(`菜单容器未找到，第 ${_menuRetries} 次重试，${delay}ms 后...`);
      _menuRetryTimer = setTimeout(_tryInjectMenu, delay);
    } else {
      warn('菜单容器始终未找到，放弃注入。请检查 SillyTavern 扩展菜单选择器是否匹配当前版本。');
    }
  }

  function _appendMenuItem(menu, pd, pj) {
    pj = pj || $j;
    if (pj(`#${MENU_ID}`, pd).length) return;

    const $wrap = pj('<div class="extension_container interactable" tabindex="0"></div>');
    const $item = pj(`
      <div class="list-group-item flex-container flexGap5 interactable" id="${MENU_ID}" title="无限流副本生成器">
        <div class="fa-fw fa-solid fa-dungeon extensionsMenuExtensionButton"></div>
        <span>副本生成器</span>
      </div>`);

    // 使用宿主 pj 绑定事件，确保事件监听器注册在正确的事件系统上
    $item.on('click', async (e) => {
      e.stopPropagation();
      try {
        const btn = pj('#extensionsMenuButton', pd);
        if (btn.length && menu.is(':visible')) { btn.trigger('click'); await new Promise(r=>setTimeout(r,150)); }
      } catch(e2) {}
      openPopup();
    });

    $wrap.append($item);
    menu.append($wrap);
    log('菜单项已添加到', menu.attr('id') || menu.attr('class'));
  }

  // MutationObserver：ST 重绘扩展菜单时自动补挂按钮
  // 用 Map 存储每个 document 对应的 observer 实例，避免静态布尔造成观察器失效后无法重装
  const _menuObservers = new Map();

  function _installMenuObserver(pd, pj) {
    // 若已有活跃 observer 绑定在这个 document 上，先检查其目标节点是否还在 DOM 里
    const existing = _menuObservers.get(pd);
    if (existing) {
      try {
        // takeRecords() 不报错说明 observer 还活着
        existing.takeRecords();
        // 再检查 body 还是同一个（ST 有时整体重建 document）
        if (pd.body) return; // observer 仍有效，不重装
      } catch(e) {
        // observer 已失效，继续安装新的
      }
      existing.disconnect();
      _menuObservers.delete(pd);
    }

    try {
      const observer = new MutationObserver(() => {
        if (!pj || !pd.body) return;
        if (pj(`#${MENU_ID}`, pd).length) return; // 已存在
        for (const sel of MENU_SELECTORS) {
          const found = pj(sel, pd);
          if (found.length) {
            _appendMenuItem(found, pd, pj);
            log('MutationObserver: 菜单项已补挂');
            break;
          }
        }
      });
      observer.observe(pd.body, { childList: true, subtree: true });
      _menuObservers.set(pd, observer);
      log('MutationObserver 已启动');
    } catch(e) {
      warn('MutationObserver 启动失败:', e);
    }
  }

  // ─────────────────────────────────────────
  // 自定义标签（主题 / 评级）
  // ─────────────────────────────────────────
  function saveCustomThemes()  { try { localStorage.setItem(STORAGE_KEY_CUSTOM_THEMES,  JSON.stringify(customThemes));  } catch(e) {} }
  function saveCustomRatings() { try { localStorage.setItem(STORAGE_KEY_CUSTOM_RATINGS, JSON.stringify(customRatings)); } catch(e) {} }

  // ─────────────────────────────────────────
  // 标签区渲染与编辑模式
  // renderTagSection(type): 统一渲染主题/评级容器 + 工具栏
  //   普通模式：所有可用按钮 + "编辑" 按钮，无删除图标，无"＋自定义"
  //   编辑模式：所有按钮 + 删除图标 + "＋自定义" + "批量导入/恢复默认/确认"
  //   全选按钮始终最后
  // ─────────────────────────────────────────
  function renderTagSection(type) {
    const $p = getPopup(); if (!$p) return;
    const isTheme    = type === 'theme';
    const contId     = isTheme ? '#dg-themes-container' : '#dg-ratings-container';
    const toolbarId  = isTheme ? '#dg-theme-toolbar'    : '#dg-rating-toolbar';
    const defaults   = isTheme ? THEMES  : RATINGS;
    const deleted    = isTheme ? deletedDefaultThemes  : deletedDefaultRatings;
    const custom     = isTheme ? customThemes  : customRatings;
    const attrKey    = isTheme ? 'data-theme'  : 'data-rating';
    const extraCls   = isTheme ? '' : ' dg-rating-btn';
    const isEdit     = _tagEditMode[type];

    const $cont    = $p.find(contId);
    const $toolbar = $p.find(toolbarId);

    // Preserve currently active values before clearing
    const activeVals = [];
    $cont.find('.dg-tag-btn').each(function() {
      if ($j(this).hasClass('active'))
        activeVals.push(isTheme ? $j(this).data('theme') : $j(this).data('rating'));
    });

    $cont.empty();

    // Predefined buttons (excluding deleted)
    defaults.filter(t => !deleted.includes(t)).forEach(t => {
      const $btn = $j(
        `<button class="dg-tag-btn${extraCls}" ${attrKey}="${esc(t)}">${esc(t)}`
        + (isEdit ? '<span class="dg-tag-del">✕</span>' : '')
        + `</button>`
      );
      if (activeVals.includes(t)) $btn.addClass('active');
      $cont.append($btn);
    });

    // Custom buttons
    custom.forEach(item => {
      const name  = typeof item === 'string' ? item : item.name;
      // desc 只存入数据供AI使用，不显示在按钮上
      const $btn  = $j(
        `<button class="dg-tag-btn dg-tag-custom${extraCls}" ${attrKey}="${esc(name)}">${esc(name)}`
        + (isEdit ? '<span class="dg-tag-del">✕</span>' : '')
        + `</button>`
      );
      if (activeVals.includes(name)) $btn.addClass('active');
      $cont.append($btn);
    });

    // "＋ 自定义" only in edit mode
    if (isEdit) {
      const addId = isTheme ? 'dg-add-theme-btn' : 'dg-add-rating-btn';
      const $addBtn = $j(`<button class="dg-tag-add-btn" id="${addId}">＋ 自定义</button>`);
      $addBtn.on('click', () => openAddTagModal(type));
      $cont.append($addBtn);
    }

    // 全选 always last
    const $all = $j(
      `<button class="dg-tag-btn dg-tag-all${extraCls}" ${attrKey}="全选">全选(随机)</button>`
    );
    if (activeVals.includes('全选')) $all.addClass('active');
    $cont.append($all);

    // ── Toolbar（编辑模式：恢复默认；普通模式：空）──
    $toolbar.empty();
    if (isEdit) {
      const $restore = $j('<button class="dg-btn dg-btn-sm" style="font-size:11px;padding:3px 8px;">恢复默认</button>');
      $restore.on('click', () => restoreTagDefaults(type));
      $toolbar.append($restore);
    }
  }

  function enterTagEditMode(type) {
    const isTheme = type === 'theme';
    // Snapshot state before edit
    _tagEditSnapshot[type] = {
      deletedDefaults: [...(isTheme ? deletedDefaultThemes : deletedDefaultRatings)],
      custom: [...(isTheme ? customThemes : customRatings).map(x =>
        typeof x === 'string' ? { name: x, desc: '' } : { ...x }
      )]
    };
    _tagEditMode[type] = true;
    renderTagSection(type);
  }

  function restoreTagDefaults(type) {
    if (type === 'theme') {
      deletedDefaultThemes = [];
      customThemes = [];
    } else {
      deletedDefaultRatings = [];
      customRatings = [];
    }
    renderTagSection(type);
    toast('info', `${type === 'theme' ? '主题' : '评级'}已恢复默认，点击面板「✓ 确认」提交`);
  }

  // 统一确认：汇总主题+评级两栏的所有改动，一次性确认保存
  function confirmTagsAll() {
    const $p = getPopup();
    const allSections = [];

    ['theme', 'rating'].forEach(type => {
      const snap = _tagEditSnapshot[type];
      const isTheme   = type === 'theme';
      const deleted   = isTheme ? deletedDefaultThemes : deletedDefaultRatings;
      const custom    = isTheme ? customThemes : customRatings;
      const typeLabel = isTheme ? '副本主题' : '危险评级';

      const snapDeleted = snap ? snap.deletedDefaults : [];
      const snapCustom  = snap ? snap.custom.map(x => x.name) : [];
      const nowCustom   = custom.map(x => typeof x === 'string' ? x : x.name);

      const newlyDeleted = [
        ...deleted.filter(n => !snapDeleted.includes(n)),
        ...snapCustom.filter(n => !nowCustom.includes(n))
      ];
      const restored   = snapDeleted.filter(n => !deleted.includes(n));
      const newlyAdded = nowCustom.filter(n => !snapCustom.includes(n));

      if (!newlyDeleted.length && !restored.length && !newlyAdded.length) return;

      let html = `<div style="font-size:11px;letter-spacing:2px;color:var(--text3);text-transform:uppercase;margin-bottom:8px;">${typeLabel}</div>`;
      if (newlyAdded.length)
        html += `<div style="margin-bottom:6px;"><span style="color:var(--accent2);">＋ 新增（${newlyAdded.length}）</span><div style="margin-top:4px;display:flex;flex-wrap:wrap;gap:4px;">${newlyAdded.map(n => `<span class="dg-tag-btn" style="pointer-events:none;font-size:11px;padding:2px 7px;">${esc(n)}</span>`).join('')}</div></div>`;
      if (newlyDeleted.length)
        html += `<div style="margin-bottom:6px;"><span style="color:#c44;">－ 删除（${newlyDeleted.length}）</span><div style="margin-top:4px;display:flex;flex-wrap:wrap;gap:4px;">${newlyDeleted.map(n => `<span class="dg-tag-btn" style="pointer-events:none;font-size:11px;padding:2px 7px;opacity:.6;text-decoration:line-through;">${esc(n)}</span>`).join('')}</div></div>`;
      if (restored.length)
        html += `<div><span style="color:var(--text2);">↩ 恢复（${restored.length}）</span><div style="margin-top:4px;display:flex;flex-wrap:wrap;gap:4px;">${restored.map(n => `<span class="dg-tag-btn" style="pointer-events:none;font-size:11px;padding:2px 7px;">${esc(n)}</span>`).join('')}</div></div>`;
      allSections.push(`<div style="margin-bottom:14px;padding-bottom:14px;border-bottom:1px solid var(--border);">${html}</div>`);
    });

    if (!allSections.length) {
      _exitTagsEditMode();
      toast('info', '无改动');
      return;
    }

    showModal({
      title: '确认保存标签改动',
      body: `<div style="font-size:13px;">${allSections.join('')}</div>`,
      footer: `<button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-tag-confirm-ok">保存</button>`
            + `<button class="dg-btn" id="dg-tag-confirm-cancel" style="padding:8px 18px;">继续编辑</button>`,
      onAfterRender: () => {
        $p.find('#dg-tag-confirm-ok').on('click', () => {
          try { localStorage.setItem(STORAGE_KEY_CUSTOM_THEMES,   JSON.stringify(customThemes));          } catch(e) {}
          try { localStorage.setItem(STORAGE_KEY_DELETED_THEMES,  JSON.stringify(deletedDefaultThemes));  } catch(e) {}
          try { localStorage.setItem(STORAGE_KEY_CUSTOM_RATINGS,  JSON.stringify(customRatings));         } catch(e) {}
          try { localStorage.setItem(STORAGE_KEY_DELETED_RATINGS, JSON.stringify(deletedDefaultRatings)); } catch(e) {}
          _exitTagsEditMode();
          closeModal();
          toast('success', '标签配置已保存');
        });
        $p.find('#dg-tag-confirm-cancel').on('click', closeModal);
      },
    });
  }

  // 取消编辑：弹出确认框，确认后从快照还原所有改动
  function cancelTagsEdit() {
    showModal({
      title: '放弃此次编辑？',
      body: `<div style="text-align:center;padding:8px 0 4px;font-size:14px;color:var(--text);">
               此次对<span style="color:var(--accent2);font-weight:700;">副本主题</span>和
               <span style="color:var(--accent2);font-weight:700;">危险评级</span>的所有改动
               <br>将被<span style="color:#c44;font-weight:700;">全部撤销</span>，无法恢复。
               <div style="font-size:11px;color:var(--text3);margin-top:8px;">点击「确认放弃」还原到编辑前的状态</div>
             </div>`,
      footer: `<button class="dg-btn dg-btn-danger" style="flex:1;" id="dg-cancel-edit-ok">确认放弃</button>`
            + `<button class="dg-btn" id="dg-cancel-edit-back" style="padding:8px 18px;">继续编辑</button>`,
      onAfterRender: () => {
        const $p = getPopup();
        $p.find('#dg-cancel-edit-ok').on('click', () => {
          // 从快照还原
          ['theme', 'rating'].forEach(type => {
            const snap = _tagEditSnapshot[type];
            if (!snap) return;
            if (type === 'theme') {
              deletedDefaultThemes = [...snap.deletedDefaults];
              customThemes = snap.custom.map(x => ({ ...x }));
            } else {
              deletedDefaultRatings = [...snap.deletedDefaults];
              customRatings = snap.custom.map(x => ({ ...x }));
            }
          });
          _exitTagsEditMode();
          closeModal();
          toast('info', '已放弃此次编辑');
        });
        $p.find('#dg-cancel-edit-back').on('click', closeModal);
      },
    });
  }

    // 退出编辑模式：重置状态，切换面板按钮，重渲两栏
  function _exitTagsEditMode() {
    const $p = getPopup();
    _tagEditMode     = { theme: false, rating: false };
    _tagEditSnapshot = { theme: null,  rating: null  };
    if ($p) {
      $p.find('#dg-tags-edit-btn').show();
      $p.find('#dg-tags-confirm-btn, #dg-tags-cancel-btn, #dg-tags-batch-btn').hide();
      renderTagSection('theme');
      renderTagSection('rating');
    }
  }

    function openBatchImportModal(defaultType) {
    showModal({
      title: '批量导入自定义选项',
      body: `
        <div style="margin-bottom:10px;">
          <div style="display:flex;gap:0;border:1px solid var(--border);border-radius:4px;overflow:hidden;margin-bottom:14px;">
            <button id="dg-bi-tab-theme"
              style="flex:1;padding:8px 0;background:var(--accent);color:#fff;border:none;cursor:pointer;font-size:13px;letter-spacing:1px;">
              副本主题
            </button>
            <button id="dg-bi-tab-rating"
              style="flex:1;padding:8px 0;background:var(--bg2);color:var(--text2);border:none;cursor:pointer;font-size:13px;letter-spacing:1px;">
              危险评级
            </button>
          </div>
          <div class="dg-hint" style="margin-bottom:8px;line-height:1.8;">
            每行一条，格式：<code style="color:var(--accent2);">名称</code> 或 <code style="color:var(--accent2);">名称|说明</code><br>
            竖线后的说明将显示在按钮括号内（选填）。
          </div>
          <textarea id="dg-bi-input" rows="10" placeholder="末世|后启示录废土设定&#10;仙侠&#10;赛博朋克|霓虹都市与黑客文化&#10;克苏鲁|未知恐惧与宇宙异变"
            style="width:100%;background:var(--input-bg);border:1px solid var(--border);
                   color:var(--input-text);padding:8px 11px;font-size:13px;font-family:inherit;
                   outline:none;box-sizing:border-box;resize:vertical;line-height:1.8;
                   border-radius:4px;"></textarea>
          <div id="dg-bi-preview" style="margin-top:10px;display:flex;flex-wrap:wrap;gap:6px;min-height:28px;"></div>
        </div>`,
      footer: '<button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-bi-confirm">一键导入</button>' + '<button class="dg-btn" id="dg-bi-cancel" style="padding:8px 18px;">取消</button>',
      onAfterRender: () => {
        const $p = getPopup();
        let currentType = defaultType || 'theme';

        // 解析输入行 → [{name, desc}]
        function parseLines() {
          const raw = $p.find('#dg-bi-input').val() || '';
          return raw.split('\n')
            .map(l => l.trim()).filter(Boolean)
            .map(l => {
              const sep = l.indexOf('|');
              if (sep > 0) return { name: l.slice(0, sep).trim(), desc: l.slice(sep + 1).trim() };
              return { name: l, desc: '' };
            })
            .filter(item => item.name);
        }

        // 实时预览按钮
        function updatePreview() {
          const items = parseLines();
          const $pv = $p.find('#dg-bi-preview');
          $pv.empty();
          items.forEach(item => {
            const label = item.desc ? `${esc(item.name)}（${esc(item.desc)}）` : esc(item.name);
            $pv.append($j(`<button class="dg-tag-btn" style="pointer-events:none;opacity:.85;">${label}</button>`));
          });
          if (!items.length) $pv.html(`<span style="color:var(--text3);font-size:12px;">预览将在此显示</span>`);
        }

        // Tab 切换
        function setTab(type) {
          currentType = type;
          const isTheme = type === 'theme';
          $p.find('#dg-bi-tab-theme').css({ background: isTheme ? 'var(--accent)' : 'var(--bg2)', color: isTheme ? '#fff' : 'var(--text2)' });
          $p.find('#dg-bi-tab-rating').css({ background: isTheme ? 'var(--bg2)' : 'var(--accent)', color: isTheme ? 'var(--text2)' : '#fff' });
        }

        $p.find('#dg-bi-tab-theme').on('click', () => setTab('theme'));
        $p.find('#dg-bi-tab-rating').on('click', () => setTab('rating'));
        $p.find('#dg-bi-input').on('input', updatePreview);
        setTab(currentType); // 初始化 tab 状态
        updatePreview();

        $p.find('#dg-bi-confirm').on('click', () => {
          const items = parseLines();
          if (!items.length) { toast('warning', '请先输入内容'); return; }

          const list = currentType === 'theme' ? customThemes : customRatings;
          const save = currentType === 'theme' ? saveCustomThemes : saveCustomRatings;
          const typeLabel = currentType === 'theme' ? '副本主题' : '危险评级';

          // 预分类：新增 vs 重复
          const toAdd = [];
          const skipped = [];
          items.forEach(item => {
            if (list.some(t => (typeof t === 'string' ? t : t.name) === item.name))
              skipped.push(item);
            else
              toAdd.push(item);
          });

          if (!toAdd.length) {
            toast('warning', `全部 ${skipped.length} 条已存在，无新增内容`);
            return;
          }

          // 构建确认框内容
          const addRows = toAdd.map(item => {
            const label = item.desc
              ? `<b style='color:var(--text);'>${esc(item.name)}</b> <span style='color:var(--text3);font-size:11px;'>（${esc(item.desc)}）</span>`
              : `<b style='color:var(--text);'>${esc(item.name)}</b>`;
            return `<div style='padding:4px 0;border-bottom:1px solid var(--border);'>${label}</div>`;
          }).join('');
          const skipNote = skipped.length
            ? `<div style='margin-top:10px;font-size:11px;color:var(--text3);'>另有 ${skipped.length} 条已存在将被跳过：${skipped.map(s=>esc(s.name)).join('、')}</div>`
            : '';

          showModal({
            title: `确认导入 ${typeLabel}`,
            body: `
              <div style='font-size:12px;color:var(--text2);margin-bottom:8px;'>以下 <b style='color:var(--accent2);'>${toAdd.length}</b> 个按钮将被添加：</div>
              <div style='max-height:200px;overflow-y:auto;'>${addRows}</div>
              ${skipNote}`,
            footer: `<button class='dg-btn dg-btn-primary' style='flex:1;' id='dg-bi-do-import'>确认添加</button>`
              + `<button class='dg-btn' id='dg-bi-back' style='padding:8px 18px;'>返回</button>`,
            onAfterRender: () => {
              $p.find('#dg-bi-do-import').on('click', () => {
                toAdd.forEach(item => list.push({ name: item.name, desc: item.desc }));
                if (!_tagEditMode[currentType]) save(); // 编辑模式下延迟到「确认」才保存
                renderTagSection(currentType);
                closeModal();
                toast('success', `已导入 ${toAdd.length} 条${skipped.length ? `，跳过 ${skipped.length} 条重复` : ''}`);
              });
              $p.find('#dg-bi-back').on('click', closeModal);
            },
          });
        });

        $p.find('#dg-bi-cancel').on('click', closeModal);
      },
    });
  }

    function openAddTagModal(type) {
    const isTheme = type === 'theme';
    const label   = isTheme ? '主题' : '评级';
    const placeholder = isTheme
      ? { name: '例：蒸汽朋克', desc: '例：工业机械与蒸汽动力的异变世界' }
      : { name: '例：XS',       desc: '例：极限挑战，通关率接近0%' };

    showModal({
      title: `添加自定义${label}`,
      body: `
        <div class="dg-field" style="margin-bottom:12px;">
          <label>${label}名称 <span style="color:var(--accent2);">*</span></label>
          <input type="text" id="dg-add-tag-name" placeholder="${placeholder.name}" style="margin-top:4px;">
        </div>
        <div class="dg-field">
          <label>说明（选填）</label>
          <div class="dg-hint" style="margin-bottom:5px;">将显示在按钮的括号内，不填则只显示名称。</div>
          <input type="text" id="dg-add-tag-desc" placeholder="${placeholder.desc}" style="margin-top:2px;">
        </div>`,
      footer: `
        <button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-add-tag-confirm">添加</button>
        <button class="dg-btn" id="dg-add-tag-cancel" style="padding:8px 16px;">取消</button>`,
      onAfterRender: () => {
        const $p = getPopup();
        $p.find('#dg-add-tag-name').focus();

        const doAdd = () => {
          const name = $p.find('#dg-add-tag-name').val().trim();
          const desc = $p.find('#dg-add-tag-desc').val().trim();
          if (!name) { toast('warning', '请输入名称'); return; }

          const exists = (arr) => arr.some(x => (typeof x === 'string' ? x : x.name) === name);

          if (isTheme) {
            if (THEMES.includes(name) || exists(customThemes)) { toast('warning', `「${name}」已存在`); return; }
            customThemes.push({ name, desc });
            if (!_tagEditMode.theme) saveCustomThemes(); // 编辑模式下延迟保存
            renderTagSection('theme');
            const $p2 = getPopup();
            $p2.find('#dg-themes-container .dg-tag-all').removeClass('active');
            $p2.find(`#dg-themes-container [data-theme="${esc(name)}"]`).addClass('active');
          } else {
            if (RATINGS.includes(name) || exists(customRatings)) { toast('warning', `「${name}」已存在`); return; }
            customRatings.push({ name, desc });
            if (!_tagEditMode.rating) saveCustomRatings(); // 编辑模式下延迟保存
            renderTagSection('rating');
            const $p2 = getPopup();
            $p2.find('#dg-ratings-container .dg-tag-all').removeClass('active');
            $p2.find(`#dg-ratings-container [data-rating="${esc(name)}"]`).addClass('active');
          }
          toast('success', `已添加自定义${label}「${name}」${desc ? `（${desc}）` : ''}`);
          closeModal();
        };

        $p.find('#dg-add-tag-confirm').on('click', doAdd);
        $p.find('#dg-add-tag-name, #dg-add-tag-desc').on('keydown', e => {
          if (e.key === 'Enter') { e.preventDefault(); doAdd(); }
        });
        $p.find('#dg-add-tag-cancel').on('click', closeModal);
      },
    });
  }

  // ─────────────────────────────────────────
  // 大总结系统
  // ─────────────────────────────────────────
  function saveSummaries() {
    try { localStorage.setItem(STORAGE_KEY_SUMMARIES, JSON.stringify(summaries)); } catch(e) {}
  }

  function renderSummaryList() {
    const $p = getPopup(); if (!$p) return;
    const $list = $p.find('#dg-summary-list');
    $list.empty();
    if (!summaries.length) {
      $list.html('<div class="dg-hint" style="text-align:center;padding:8px;">暂无大总结，点击上方按钮添加。</div>');
      return;
    }
    summaries.forEach((s, idx) => {
      const $item = $j(`
        <div style="background:var(--bg3);border:1px solid var(--border);padding:10px 12px;border-left:3px solid var(--accent);margin-bottom:5px;">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px;">
            <span style="font-size:13px;font-weight:700;color:var(--accent2);">${esc(s.name)}</span>
            <div style="display:flex;gap:5px;">
              <button class="dg-btn dg-btn-sm dg-summary-edit-btn" data-idx="${idx}" style="font-size:10px;padding:2px 7px;letter-spacing:0;">编辑</button>
              <button class="dg-btn dg-btn-sm dg-btn-danger dg-summary-del-btn" data-idx="${idx}" style="font-size:10px;padding:2px 7px;letter-spacing:0;">删</button>
            </div>
          </div>
          <div style="font-size:11px;color:var(--text3);font-family:'Courier New',monospace;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${esc((s.content||'').replace(/\n/g,' ').slice(0,80))}${(s.content||'').length>80?'…':''}</div>
        </div>`);
      $list.append($item);
    });
  }

  function renderSummaryInjectSelect() {
    const $p = getPopup(); if (!$p) return;
    const $sel = $p.find('#dg-summary-inject-select');
    const cur = $sel.val();
    $sel.empty().append('<option value="">— 不注入 —</option>');
    summaries.forEach(s => $sel.append($j('<option>').val(s.id).text(s.name)));
    if (cur && summaries.find(s => s.id === cur)) $sel.val(cur);
  }

  function openAddSummaryModal(existingIdx) {
    const existing = (existingIdx !== undefined && existingIdx >= 0) ? summaries[existingIdx] : null;
    showModal({
      title: existing ? '编辑大总结' : '添加大总结',
      body: `
        <div class="dg-field" style="margin-bottom:10px;">
          <label>标题 <span style="color:var(--accent2);">*</span></label>
          <input type="text" id="dg-sum-name" placeholder="例：第一章剧情总结" style="margin-top:4px;" value="${esc(existing ? existing.name : '')}">
        </div>
        <div class="dg-field">
          <label>大总结内容 <span style="color:var(--accent2);">*</span></label>
          <textarea id="dg-sum-content" rows="10" placeholder="在此粘贴或撰写大总结内容..."
            style="width:100%;background:var(--input-bg);border:1px solid var(--border);
                   color:var(--input-text);padding:8px 11px;font-size:13px;font-family:inherit;
                   outline:none;box-sizing:border-box;resize:vertical;line-height:1.6;"
          >${esc(existing ? existing.content : '')}</textarea>
        </div>`,
      footer: `<button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-sum-save-btn">保存</button>
               <button class="dg-btn" id="dg-sum-cancel-btn" style="padding:8px 18px;">取消</button>`,
      onAfterRender: () => {
        const $p = getPopup();
        $p.find('#dg-sum-name').focus();
        $p.find('#dg-sum-save-btn').on('click', () => {
          const name    = $p.find('#dg-sum-name').val().trim();
          const content = $p.find('#dg-sum-content').val().trim();
          if (!name)    { toast('warning', '请输入标题'); return; }
          if (!content) { toast('warning', '请输入内容'); return; }
          if (existing) {
            summaries[existingIdx] = { ...existing, name, content };
          } else {
            summaries.push({ id: 'sum_' + Date.now() + '_' + Math.random().toString(36).slice(2,6), name, content });
          }
          saveSummaries();
          renderSummaryList();
          renderSummaryInjectSelect();
          closeModal();
          toast('success', existing ? '大总结已更新' : '大总结已保存');
        });
        $p.find('#dg-sum-cancel-btn').on('click', closeModal);
      },
    });
  }

