            style="width:100%;background:var(--input-bg);border:1px solid var(--border);
                   color:var(--input-text);padding:8px 11px;font-size:13px;font-family:inherit;
                   outline:none;box-sizing:border-box;resize:vertical;line-height:1.6;"
          >${esc(summaryReq)}</textarea>
        </div>
        <div id="dg-aisum-result-wrap" style="display:none;">
          <div class="dg-field">
            <label>生成结果（预览）</label>
            <textarea id="dg-aisum-result" rows="8" readonly
              style="width:100%;background:var(--bg3);border:1px solid var(--border);
                     color:var(--input-text);padding:8px 11px;font-size:12px;font-family:'Courier New',monospace;
                     outline:none;box-sizing:border-box;resize:vertical;line-height:1.6;"></textarea>
          </div>
          <div class="dg-field">
            <label>保存标题 <span style="color:var(--accent2);">*</span></label>
            <input type="text" id="dg-aisum-save-name" placeholder="为这条大总结命名..." style="margin-top:4px;">
          </div>
        </div>`,
      footer: `<button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-aisum-gen-btn">✦ 生成大总结</button>
               <button class="dg-btn" id="dg-aisum-save-btn" style="display:none;flex:1;padding:8px 12px;">💾 保存</button>
               <button class="dg-btn" id="dg-aisum-cancel-btn" style="padding:8px 18px;">取消</button>`,
      onAfterRender: () => {
        const $p = getPopup();
        const $psel = $p.find('#dg-aisum-preset-sel');
        savedPresets.forEach((pr, i) => $psel.append($j('<option>').val(i).text(pr.name)));

        $p.find('#dg-aisum-load-preset').on('click', () => {
          const idx = parseInt($psel.val());
          if (isNaN(idx) || !savedPresets[idx]) { toast('warning', '请先选择预设'); return; }
          const pr = savedPresets[idx];
          if (pr.apiConfig) { apiConfig = { ...apiConfig, ...pr.apiConfig }; updateApiStatus(); toast('info', `已临时载入预设「${pr.name}」`); }
        });

        $p.find('#dg-aisum-upload-btn').on('click', () => $p.find('#dg-aisum-file').val('').trigger('click'));
        $p.find('#dg-aisum-file').on('change', function() {
          const file = this.files[0]; if (!file) return;
          const reader = new FileReader();
          reader.onload = (ev) => {
            $p.find('#dg-aisum-content').val(ev.target.result);
            $p.find('#dg-aisum-file-info').text(`已载入：${file.name}（${(file.size/1024).toFixed(1)} KB）`);
          };
          reader.readAsText(file, 'utf-8');
        });
        $p.find('#dg-aisum-clear-btn').on('click', () => {
          $p.find('#dg-aisum-content').val('');
          $p.find('#dg-aisum-file-info, #dg-aisum-fetch-info').text('');
        });

        $p.find('#dg-aisum-fetch-btn').on('click', () => {
          const tag = ($p.find('#dg-aisum-tag').val().trim() || 'content').replace(/[<>\/]/g, '');
          try {
            const ctx = ST && ST.getContext ? ST.getContext() : null;
            if (!ctx || !Array.isArray(ctx.chat) || !ctx.chat.length) {
              toast('warning', '未获取到聊天记录，请确认已进入对话'); return;
            }
            const allText = ctx.chat.map(m => m.mes || '').join('\n');
            const regex = new RegExp(`<${tag}>[\\s\\S]*?<\\/${tag}>`, 'gi');
            const matches = allText.match(regex) || [];
            if (!matches.length) {
              $p.find('#dg-aisum-fetch-info').text(`未找到 <${tag}>...</${tag}> 标签`);
              toast('warning', `未找到 <${tag}> 标签`); return;
            }
            const extracted = matches
              .map(m => m.replace(new RegExp(`^<${tag}>|<\\/${tag}>$`, 'gi'), '').trim())
              .filter(Boolean).join('\n\n');
            $p.find('#dg-aisum-content').val(extracted);
            $p.find('#dg-aisum-fetch-info').text(`✓ 找到 ${matches.length} 处 <${tag}> 内容，共 ${extracted.length} 字符`);
            toast('success', `已提取 ${matches.length} 处 <${tag}> 内容`);
          } catch(e) { toast('error', `获取失败：${e.message}`); }
        });

        $p.find('#dg-aisum-req').on('input', function() {
          summaryReq = $j(this).val();
          try { localStorage.setItem(STORAGE_KEY_SUMMARY_REQ, summaryReq); } catch(e) {}
        });

        $p.find('#dg-aisum-gen-btn').on('click', async () => {
          const content = $p.find('#dg-aisum-content').val().trim();
          const req     = $p.find('#dg-aisum-req').val().trim();
          if (!content) { toast('warning', '请先输入主线内容'); return; }
          if (!req)     { toast('warning', '请填写总结要求'); return; }
          if (!apiConfig.url || !apiConfig.model) { toast('error', '请先配置API'); return; }
          const prompt = SUMMARY_PROMPT_TPL.replace('{{req}}', req).replace('{{content}}', content);
          const $btn = $p.find('#dg-aisum-gen-btn');
          $btn.prop('disabled', true).text('生成中...');
          try {
            const result = await callAI(prompt);
            $p.find('#dg-aisum-result').val(result);
            $p.find('#dg-aisum-result-wrap').show();
            $p.find('#dg-aisum-save-btn').show();
            $p.find('#dg-aisum-save-name').focus();
            toast('success', '大总结生成完成，请检查后保存');
          } catch(e) { toast('error', `生成失败：${e.message}`); }
          finally { $btn.prop('disabled', false).text('✦ 重新生成'); }
        });

        $p.find('#dg-aisum-save-btn').on('click', () => {
          const name    = $p.find('#dg-aisum-save-name').val().trim();
          const content = $p.find('#dg-aisum-result').val().trim();
          if (!name)    { toast('warning', '请输入保存标题'); return; }
          if (!content) { toast('warning', '内容为空，无法保存'); return; }
          summaries.push({ id: 'sum_' + Date.now() + '_' + Math.random().toString(36).slice(2,6), name, content });
          saveSummaries();
          renderSummaryList();
          renderSummaryInjectSelect();
          closeModal();
          toast('success', `大总结「${name}」已保存`);
        });

        $p.find('#dg-aisum-cancel-btn').on('click', closeModal);
      },
    });
  }

