  // ─────────────────────────────────────────
  // 弹窗管理（常驻 DOM）
  // shell+popup 在 init 时一次性注入宿主 body，打开/关闭只切换 display
  // 动态内容由 _syncPopupState() 在每次打开时同步，事件只绑定一次
  // ─────────────────────────────────────────
  let _popupOpening = false;
  let _shellCreated = false;

  // 将 shell CSS 单独注入宿主 document <head>（一次，幂等）
  // 参考 Quick CSS Editor 的 injectStylesAndLibraries 模式
  function _injectShellStyles(hd) {
    if (hd.getElementById(_SHELL_STYLE_ID)) return;
    const css = `
      /* DungeonGen Shell — 注入到宿主 document */
      #${SHELL_ID} {
        display: none;
        position: fixed;
        top: 0; left: 0; right: 0; bottom: 0;
        width: 100%; height: 100%;
        z-index: 99990;
        -webkit-overflow-scrolling: touch;
      }
      /* 桌面端：flex 居中 + 半透明遮罩 */
      @media (min-width: 769px) {
        #${SHELL_ID}.dg-shell-visible {
          display: flex !important;
          justify-content: center;
          align-items: flex-start;
          overflow-y: auto;
          padding: 16px;
          box-sizing: border-box;
          background: rgba(0,0,0,.45);
          backdrop-filter: blur(3px);
          -webkit-backdrop-filter: blur(3px);
        }
      }
      /* 桌面端：popup 使用 flex 列布局，header 自然钉顶，scroll body 自身滚动
         关键：
         1. overflow:hidden 让 max-height 真正生效（否则 flex 子元素仍可溢出）
         2. flex:1 1 auto（非 0）— basis:0 会导致 scroll body 贡献 0 高度，
            popup 高度坍缩为仅 header，内容全部不可见 */
      @media (min-width: 769px) {
        #${POPUP_ID} {
          max-height: calc(100vh - 32px);
          overflow: hidden;   /* 必须：否则子元素仍可撑破 max-height */
          display: flex;
          flex-direction: column;
        }
        #${POPUP_ID} .dg-sticky-header { flex-shrink: 0; }
        #${POPUP_ID} .dg-scroll-body {
          flex: 1 1 auto;     /* auto：scroll body 自身内容参与高度计算，不坍缩 */
          min-height: 0;      /* 允许在内容超出时收缩并触发 overflow 滚动 */
          overflow-y: auto;
          -webkit-overflow-scrolling: touch;
        }
      }
      /* 移动端：铺满全屏，使用 dvh 处理动态视口 */
      @media (max-width: 768px) {
        #${SHELL_ID}.dg-shell-visible {
          display: block !important;
          overflow-y: auto;
          height: 100vh;
          height: 100dvh;
        }
        #${POPUP_ID} {
          min-width: unset !important;
          max-width: 100% !important;
          width: 100% !important;
          min-height: 100vh;
          min-height: 100dvh;
          margin: 0 !important;
          display: flex !important;
          flex-direction: column !important;
        }
        /* flex:1 + min-height:0 解决 sticky header + overflow 层叠问题 */
        #${POPUP_ID} .dg-scroll-body {
          flex: 1 1 0 !important;
          min-height: 0 !important;
          overflow-y: auto !important;
          -webkit-overflow-scrolling: touch;
        }
        #${POPUP_ID} .dg-generate-bar { flex-shrink: 0; }
      }
    `;
    const style = hd.createElement('style');
    style.id = _SHELL_STYLE_ID;
    style.textContent = css;
    (hd.head || hd.documentElement).appendChild(style);
    log('_injectShellStyles: 已注入宿主 document');
  }

  // 一次性创建 shell + popup DOM 并绑定事件（init 时调用）
  function _createShellDOM() {
    if (_shellCreated) return true;
    const H$ = getHostJQ() || $j;
    const hd = getHostDocument();
    const hw = getHostWindow();

    // 幂等：DOM 已存在则直接复用（FLAG 保护下不会重复，但防御性检查）
    if (H$(`#${SHELL_ID}`, hd).length) {
      $popup = H$(`#${POPUP_ID}`, hd);
      _shellCreated = true;
      return true;
    }

    try {
      _injectShellStyles(hd);

      const html = buildPopupHTML();
      const $shell = H$(`<div id="${SHELL_ID}"></div>`);
      $shell.html(html);
      H$(hd.body).append($shell);

      $popup = H$(`#${POPUP_ID}`, hd);
      if (!$popup.length) throw new Error('popup DOM 未找到');

      // 桌面端：点击遮罩关闭
      // 追踪 mousedown 起点，防止从 popup 拖拽到遮罩时误触关闭
      let _shellMdX = 0, _shellMdY = 0, _shellMdOnOverlay = false;
      $shell.on('mousedown', function(e) {
        _shellMdOnOverlay = (e.target === this);
        _shellMdX = e.clientX;
        _shellMdY = e.clientY;
      });
      $shell.on('click', function(e) {
        if (e.target !== this) return;         // 点到了 popup 内部，不关
        if (!_shellMdOnOverlay) return;         // mousedown 起点不在遮罩，是拖拽，不关
        const dx = Math.abs(e.clientX - _shellMdX);
        const dy = Math.abs(e.clientY - _shellMdY);
        if (dx < 5 && dy < 5) _closePopupShell(); // 真实单击才关闭
      });
      // ESC 关闭
      H$(hd).on('keydown.dgShell', function(e) {
        if (e.key === 'Escape') _closePopupShell();
      });

      // 事件绑定只做一次
      bindEvents();

      // 移动端键盘弹出适配（参考 Quick CSS Editor visualViewport 方案）
      const vp = hw.visualViewport || (typeof visualViewport !== 'undefined' ? visualViewport : null);
      if (vp) {
        vp.addEventListener('resize', () => {
          const $sh = H$(`#${SHELL_ID}`, hd);
          if (!$sh.hasClass('dg-shell-visible')) return;
          const screenH = hw.screen && hw.screen.height ? hw.screen.height : (hw.innerHeight || 800);
          if ((hw.innerWidth || 800) > 768) return; // 仅移动端处理
          if (vp.height < screenH * 0.75) {
            // 键盘弹出：shell 缩至可视区域
            $sh.css({ height: vp.height + 'px', top: (vp.offsetTop || 0) + 'px' });
          } else {
            // 键盘收起：还原
            $sh.css({ height: '', top: '0' });
          }
        });
      }

      _shellCreated = true;
      log('_createShellDOM: 完成，DOM 已常驻');
      return true;
    } catch(e) {
      err('_createShellDOM 失败:', e);
      return false;
    }
  }

  // 关闭弹窗：隐藏 shell，DOM 不销毁（常驻）
  function _closePopupShell() {
    const H$ = getHostJQ() || $j;
    const hd = getHostDocument();
    closeModal(); // 先关闭 popup 内的模态框
    H$(`#${SHELL_ID}`, hd).removeClass('dg-shell-visible').hide();
    // $popup 保留引用，DOM 常驻
  }

  // 同步动态内容（每次打开时调用，将当前状态写入持久 DOM）
  function _syncPopupState() {
    const $p = $popup;
    if (!$p || !$p.length) return;

    // 1. 主题 class
    $p.removeClass('dg-dark dg-light dg-cyber dg-guofeng').addClass(`dg-${currentTheme}`);

    // 2. API 表单字段
    $p.find('#dg-api-url').val(apiConfig.url    || '');
    $p.find('#dg-api-key').val(apiConfig.apiKey || '');

    // 4. Persona 按钮状态
    const hasCustom = customPersonaText && customPersonaText.trim();
    $p.find('#dg-edit-persona-btn')
      .text(hasCustom ? '✎ 已编辑' : '✎ 编辑')
      .css(hasCustom
        ? { background:'var(--accent)', borderColor:'var(--accent2)', color:'#fff' }
        : { background:'', borderColor:'', color:'' });

    // 5. 提示词（可能在其他地方被修改）
    $p.find('#dg-prompt-editor').val(currentPrompt);

    // 6. 预设下拉列表
    renderPresets();
    renderInjectionPresets();
    renderPromptPresets();
    renderGenPresets();

    // 7. 重置编辑模式（每次打开都从普通模式开始）
    _tagEditMode = { theme: false, rating: false };
    _tagEditSnapshot = { theme: null, rating: null };
    // 8. 渲染标签区（统一渲染：预设+自定义+工具栏）
    renderTagSection('theme');
    renderTagSection('rating');

    // 9. API 状态文字
    updateApiStatus();

    // 10. 大总结
    renderSummaryList();
    renderSummaryInjectSelect();
  }

  // 打开弹窗
  function openPopup() {
    if (_popupOpening) return;

    // 僵尸引用检测：$popup 存在但已离开宿主 DOM
    if ($popup && $popup.length) {
      let alive = false;
      try { alive = !!(getHostJQ()(`#${POPUP_ID}`, getHostDocument()).length); } catch(e) {}
      if (!alive) {
        log('openPopup: $popup 引用失效，重置');
        $popup = null;
        _shellCreated = false;
      }
    }

    _popupOpening = true;
    try {
      loadApis();
      loadSettings();

      // 确保 DOM 已创建（正常情况在 init 时已完成）
      if (!_shellCreated) {
        const ok = _createShellDOM();
        if (!ok) {
          // 降级：native dialog
          warn('_createShellDOM 失败，降级到 _openNativeDialog');
          try { _openNativeDialog(); }
          catch(e2) {
            err('_openNativeDialog 也失败:', e2);
            toast('error', '弹窗打开失败，请刷新页面后重试', { timeOut: 6000 });
          }
          return; // native dialog 内部已完成同步，不走后续 show 逻辑
        }
      }

      // 同步动态状态
      _syncPopupState();

      // 显示 shell
      const H$ = getHostJQ() || $j;
      const hd = getHostDocument();
      const hw = getHostWindow();
      const isMobile = (hw.innerWidth || 800) <= 768;
      H$(`#${SHELL_ID}`, hd)
        .addClass('dg-shell-visible')
        .css('display', isMobile ? 'block' : 'flex');

      log('openPopup: 弹窗已显示');
    } catch(e) {
      err('openPopup failed:', e);
      toast('error', `弹窗打开失败: ${e.message}`, { timeOut: 5000 });
    } finally {
      _popupOpening = false;
    }
  }

  // 降级路径：native dialog（_createShellDOM 失败时使用）
  function _openNativeDialog() {
    const H$ = getHostJQ() || $j;
    const hd = getHostDocument();
    H$('#dg-native-dialog', hd).remove();

    const $dlg = H$(`<dialog id="dg-native-dialog" style="
      padding:0;border:none;background:transparent;
      max-width:900px;width:95vw;max-height:92vh;overflow-y:auto;z-index:99990;
    ">${buildPopupHTML()}<div style="text-align:center;padding:12px;">
      <button id="dg-native-close" style="background:#5c0000;border:1px solid #8b0000;
        color:#fff;padding:8px 24px;cursor:pointer;font-size:13px;">关闭</button>
    </div></dialog>`);
    H$(hd.body).append($dlg);

    try { $dlg[0].showModal(); } catch(e) {
      warn('showModal() 不支持，回退为 fixed 定位:', e);
      $dlg.css({ display:'block', position:'fixed', top:'50%', left:'50%',
        transform:'translate(-50%,-50%)', zIndex:'99990', overflow:'auto' });
    }

    $popup = H$(`#${POPUP_ID}`, hd);
    if ($popup.length) {
      // 降级路径：需要临时绑定事件和同步状态
      bindEvents();
      _syncPopupState();
    }

    $dlg.find('#dg-native-close').on('click', () => {
      try { $dlg[0].close(); } catch(e) {}
      $dlg.remove();
      $popup = null;
    });
  }
  function getPopup() { return $popup; }

  // ─────────────────────────────────────────
  // 事件绑定
  // ─────────────────────────────────────────
  function bindEvents() {
    const $p = getPopup(); if (!$p) return;

    $p.find('#dg-shell-close-btn').on('click', _closePopupShell);
    $p.find('#dg-nav-gen').on('click', () => switchView('generator'));
    $p.find('#dg-tags-edit-btn').on('click', () => {
      enterTagEditMode('theme');
      enterTagEditMode('rating');
      $p.find('#dg-tags-edit-btn').hide();
      $p.find('#dg-tags-confirm-btn, #dg-tags-cancel-btn, #dg-tags-batch-btn').show();
    });
    $p.find('#dg-tags-confirm-btn').on('click', confirmTagsAll);
    $p.find('#dg-tags-cancel-btn').on('click', cancelTagsEdit);
    $p.find('#dg-tags-batch-btn').on('click', () => openBatchImportModal());
    $p.find('#dg-nav-set').on('click', () => switchView('settings'));

    // 事件委托：标签选择（容器内容动态渲染，需委托给静态父元素）
    $p.on('click', '#dg-themes-container .dg-tag-btn', function(e) {
      if ($j(e.target).hasClass('dg-tag-del')) return;
      if (_tagEditMode.theme) return; // 编辑模式下不可选中
      const val = $j(this).data('theme');
      if (val === '全选') {
        $p.find('#dg-themes-container .dg-tag-btn').removeClass('active');
        $j(this).addClass('active');
      } else {
        $p.find('#dg-themes-container .dg-tag-all').removeClass('active');
        $j(this).toggleClass('active');
      }
    });
    $p.on('click', '#dg-ratings-container .dg-tag-btn', function(e) {
      if ($j(e.target).hasClass('dg-tag-del')) return;
      if (_tagEditMode.rating) return; // 编辑模式下不可选中
      const val = $j(this).data('rating');
      if (val === '全选') {
        $p.find('#dg-ratings-container .dg-tag-btn').removeClass('active');
        $j(this).addClass('active');
      } else {
        $p.find('#dg-ratings-container .dg-tag-all').removeClass('active');
        $j(this).toggleClass('active');
      }
    });
    // 事件委托：编辑模式删除按钮
    $p.on('click', '#dg-themes-container .dg-tag-del', function(e) {
      e.stopPropagation();
      const $btn = $j(this).closest('.dg-tag-btn');
      const name = $btn.data('theme');
      if ($btn.hasClass('dg-tag-custom')) {
        customThemes = customThemes.filter(x => (typeof x === 'string' ? x : x.name) !== name);
      } else {
        if (!deletedDefaultThemes.includes(name)) deletedDefaultThemes.push(name);
      }
      renderTagSection('theme');
    });
    $p.on('click', '#dg-ratings-container .dg-tag-del', function(e) {
      e.stopPropagation();
      const $btn = $j(this).closest('.dg-tag-btn');
      const name = $btn.data('rating');
      if ($btn.hasClass('dg-tag-custom')) {
        customRatings = customRatings.filter(x => (typeof x === 'string' ? x : x.name) !== name);
      } else {
        if (!deletedDefaultRatings.includes(name)) deletedDefaultRatings.push(name);
      }
      renderTagSection('rating');
    });

    ['dg-mode-group','dg-teammate-group','dg-lang-group','dg-context-group'].forEach(gid => {
      $p.find(`#${gid} .dg-opt-btn`).on('click', function () {
        $p.find(`#${gid} .dg-opt-btn`).removeClass('active');
        $j(this).addClass('active');
        if (gid === 'dg-context-group') $p.find('#dg-context-extra').toggle($j(this).data('val') === '是');
      });
    });
    $p.find('#dg-user-special-chk').on('change', function () {
      $p.find('#dg-user-special-extra').toggle($j(this).is(':checked'));
    });
    $p.find('#dg-user-identity-group .dg-opt-btn').on('click', function () {
      $p.find('#dg-user-identity-group .dg-opt-btn').removeClass('active');
      $j(this).addClass('active');
      $p.find('#dg-user-identity-other-wrap').toggle($j(this).data('val') === '其他');
    });

    $p.find('#dg-goto-injection').on('click', () => {
      switchView('settings');
      const $hdr  = $p.find('#dg-set-world-hdr');
      const $body = $p.find('#dg-set-world-body');
      if ($hdr.hasClass('collapsed')) {
        $hdr.removeClass('collapsed');
        $body.show().css('maxHeight', '');
      }
      setTimeout(() => {
        const el = $p.find('#dg-set-world-hdr')[0];
        if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 120);
    });

    $p.find('#dg-generate-btn').on('click', handleGenerate);

    ['dg-set-theme-hdr','dg-set-api-hdr','dg-set-world-hdr','dg-set-summary-hdr','dg-set-prompt-hdr','dg-set-export-hdr'].forEach(id => {
      $p.find(`#${id}`).on('click', function () {
        $j(this).toggleClass('collapsed');
        const $b = $p.find(`#${id.replace('-hdr','-body')}`);
        if ($b.is(':visible')) {
          $b.css('maxHeight',$b[0].scrollHeight+'px'); setTimeout(()=>$b.css('maxHeight','0'),10); setTimeout(()=>$b.hide(),310);
        } else {
          $b.show().css('maxHeight','0'); setTimeout(()=>$b.css('maxHeight',$b[0].scrollHeight+'px'),10); setTimeout(()=>$b.css('maxHeight',''),310);
        }
      });
    });

    $p.find('#dg-load-models-btn').on('click', loadModels);
    $p.find('#dg-save-api-btn').on('click',    saveApiConfig);
    $p.find('#dg-clear-api-btn').on('click',   clearApiConfig);

    // 生成器预设
    $p.find('#dg-gen-save-btn').on('click', saveGenPreset);
    $p.find('#dg-gen-load-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-gen-preset-select').val());
      if (!isNaN(idx) && savedGenPresets[idx]) loadGenPreset(savedGenPresets[idx]);
      else toast('warning', '请先选择一个预设');
    });
    $p.find('#dg-gen-del-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-gen-preset-select').val());
      if (isNaN(idx) || !savedGenPresets[idx]) { toast('warning', '请先选择一个预设'); return; }
      const name = savedGenPresets[idx].name;
      confirmDelete(`生成器预设「${name}」`, () => {
        savedGenPresets.splice(idx, 1);
        try { localStorage.setItem(STORAGE_KEY_GEN_PRESETS, JSON.stringify(savedGenPresets)); } catch(e) {}
        renderGenPresets(); toast('info', `预设 "${name}" 已删除`);
      });
    });

    // 配置预设（API面板）
    $p.find('#dg-save-preset-btn').on('click', saveCurrentPreset);
    $p.find('#dg-load-preset-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-preset-select').val());
      if (!isNaN(idx) && savedPresets[idx]) loadPresetCfg(savedPresets[idx]);
      else toast('warning', '请先选择一个预设');
    });
    $p.find('#dg-del-preset-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-preset-select').val());
      if (isNaN(idx) || !savedPresets[idx]) { toast('warning', '请先选择一个预设'); return; }
      const name = savedPresets[idx].name;
      confirmDelete(`API预设「${name}」`, () => {
        savedPresets.splice(idx, 1);
        try { localStorage.setItem(STORAGE_KEY_PRESETS, JSON.stringify(savedPresets)); } catch(e) {}
        renderPresets(); toast('info', `预设 "${name}" 已删除`);
      });
    });

    $p.find('#dg-summary-add-btn').on('click', () => openAddSummaryModal());
    $p.find('#dg-summary-ai-btn').on('click',  () => openAiSummaryModal());
    $p.on('click', '.dg-summary-edit-btn', function() {
      const idx = parseInt($j(this).data('idx')); if (!isNaN(idx)) openAddSummaryModal(idx);
    });
    $p.on('click', '.dg-summary-del-btn', function() {
      const idx = parseInt($j(this).data('idx')); if (isNaN(idx)) return;
      confirmDelete(`大总结「${esc(summaries[idx].name)}」`, () => {
        summaries.splice(idx, 1); saveSummaries(); renderSummaryList(); renderSummaryInjectSelect();
      });
    });
    $p.find('#dg-refresh-lorebook').on('click', loadLorebookEntries);
    $p.find('#dg-inj-save-btn').on('click', saveInjectionPreset);
    $p.find('#dg-inj-load-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-inj-preset-select').val());
      if (!isNaN(idx) && savedInjectionPresets[idx]) loadInjectionPreset(savedInjectionPresets[idx]);
      else toast('warning', '请先选择一个注入预设');
    });
    $p.find('#dg-inj-del-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-inj-preset-select').val());
      if (isNaN(idx) || !savedInjectionPresets[idx]) { toast('warning', '请先选择一个注入预设'); return; }
      const name = savedInjectionPresets[idx].name;
      confirmDelete(`注入预设「${name}」`, () => {
        savedInjectionPresets.splice(idx, 1);
        try { localStorage.setItem(STORAGE_KEY_INJECTION_PRESETS, JSON.stringify(savedInjectionPresets)); } catch(e) {}
        renderInjectionPresets(); toast('info', `注入预设 "${name}" 已删除`);
      });
    });

    $p.find('#dg-theme-dark-btn').on('click',    () => setTheme('dark'));
    $p.find('#dg-theme-light-btn').on('click',   () => setTheme('light'));
    $p.find('#dg-theme-cyber-btn').on('click',   () => setTheme('cyber'));
    $p.find('#dg-theme-guofeng-btn').on('click', () => setTheme('guofeng'));
    $p.find('#dg-edit-persona-btn').on('click', openPersonaEditor);

    $p.find('#dg-save-prompt-btn').on('click', () => {
      currentPrompt = $p.find('#dg-prompt-editor').val();
      try { localStorage.setItem(STORAGE_KEY_PROMPT, currentPrompt); } catch(e) {}
      toast('success','提示词已保存');
    });
    $p.find('#dg-reset-prompt-btn').on('click', () => {
      currentPrompt = DEFAULT_PROMPT;
      $p.find('#dg-prompt-editor').val(currentPrompt);
      try { localStorage.removeItem(STORAGE_KEY_PROMPT); } catch(e) {}
      toast('info','提示词已恢复默认');
    });
    $p.find('#dg-prompt-save-btn').on('click', savePromptPreset);
    $p.find('#dg-prompt-load-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-prompt-preset-select').val());
      if (!isNaN(idx) && savedPromptPresets[idx]) loadPromptPreset(savedPromptPresets[idx]);
      else toast('warning', '请先选择一个提示词预设');
    });
    $p.find('#dg-prompt-del-btn').on('click', () => {
      const idx = parseInt($p.find('#dg-prompt-preset-select').val());
      if (isNaN(idx) || !savedPromptPresets[idx]) { toast('warning', '请先选择一个提示词预设'); return; }
      const name = savedPromptPresets[idx].name;
      confirmDelete(`提示词预设「${name}」`, () => {
        savedPromptPresets.splice(idx, 1);
        try { localStorage.setItem(STORAGE_KEY_PROMPT_PRESETS, JSON.stringify(savedPromptPresets)); } catch(e) {}
        renderPromptPresets(); toast('info', `提示词预设 "${name}" 已删除`);
      });
    });

    // API 表单字段由 _syncPopupState() 在每次打开时同步，此处不重复设置

    // 导出预设（按条目选择）
    $p.find('#dg-export-btn').on('click', () => {
      // 构建三个分组的条目列表
      const groups = [
        { label: '生成器预设',    key: 'genPresets',    list: savedGenPresets },
        { label: '世界观注入预设', key: 'injPresets',    list: savedInjectionPresets },
        { label: '提示词预设',    key: 'promptPresets', list: savedPromptPresets },
      ].filter(g => g.list.length > 0);

      if (!groups.length) { toast('warning', '暂无已保存的预设可导出'); return; }

      // 构建勾选列表 HTML，每组一个标题 + 条目复选框
      const bodyHtml = groups.map(g => `
        <div style="margin-bottom:12px;">
          <div style="font-size:11px;letter-spacing:2px;color:var(--text3);text-transform:uppercase;margin-bottom:6px;
                      display:flex;align-items:center;gap:6px;">
            <input type="checkbox" class="dg-export-group-chk" data-key="${g.key}" checked
                   style="width:auto;margin:0;cursor:pointer;" title="全选/全不选">
            ${esc(g.label)}
          </div>
          <div style="display:flex;flex-direction:column;gap:4px;padding-left:18px;">
            ${g.list.map((pr, i) => `
              <label style="display:flex;align-items:center;gap:6px;font-size:13px;cursor:pointer;
                            text-transform:none;letter-spacing:0;color:var(--text);">
                <input type="checkbox" class="dg-export-item-chk" checked
                       data-key="${g.key}" data-idx="${i}" style="width:auto;margin:0;cursor:pointer;">
                ${esc(pr.name)}
              </label>`).join('')}
          </div>
        </div>`).join('');

      showModal({
        title: '选择要导出的预设',
        body: `<div style="font-size:12px;color:var(--text2);margin-bottom:10px;">勾选后点击确认导出。</div>${bodyHtml}`,
        footer: `<button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-export-confirm">确认导出</button>`
              + `<button class="dg-btn" id="dg-export-cancel" style="padding:8px 18px;">取消</button>`,
        onAfterRender: () => {
          // 分组全选/全不选
          $p.find('.dg-export-group-chk').on('change', function() {
            const key = $j(this).data('key');
            const checked = $j(this).is(':checked');
            $p.find(`.dg-export-item-chk[data-key="${key}"]`).prop('checked', checked);
          });
          // 条目变化时同步组复选框
          $p.find('.dg-export-item-chk').on('change', function() {
            const key = $j(this).data('key');
            const allChk = $p.find(`.dg-export-item-chk[data-key="${key}"]`);
            const checkedCount = allChk.filter(':checked').length;
            $p.find(`.dg-export-group-chk[data-key="${key}"]`).prop({
              checked: checkedCount === allChk.length,
              indeterminate: checkedCount > 0 && checkedCount < allChk.length,
            });
          });

          $p.find('#dg-export-confirm').on('click', () => {
            const payload = {};
            const summary = [];
            groups.forEach(g => {
              const selected = [];
              $p.find(`.dg-export-item-chk[data-key="${g.key}"]:checked`).each(function() {
                const idx = parseInt($j(this).data('idx'));
                if (!isNaN(idx) && g.list[idx]) selected.push(g.list[idx]);
              });
              if (selected.length) {
                payload[g.key] = selected;
                selected.forEach(pr => summary.push(`[${g.label}] ${pr.name}`));
              }
            });
            if (!summary.length) { toast('warning', '请至少勾选一个预设'); return; }
            const json = JSON.stringify({ _dgPresetExport: true, ...payload }, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url  = URL.createObjectURL(blob);
            const a    = (getHostDocument() || document).createElement('a');
            a.href = url; a.download = `DungeonGen_Presets_${Date.now()}.json`;
            a.click(); URL.revokeObjectURL(url);
            closeModal();
            toast('success', `已导出 ${summary.length} 个预设`);
          });
          $p.find('#dg-export-cancel').on('click', closeModal);
        },
      });
    });

    // 导入预设
    $p.find('#dg-import-btn').on('click', () => {
      $p.find('#dg-import-file').val('').trigger('click');
    });
    $p.find('#dg-import-file').on('change', function() {
      const file = this.files[0]; if (!file) return;
      const reader = new FileReader();
      reader.onload = (e) => {
        let data;
        try { data = JSON.parse(e.target.result); } catch(err) { toast('error', '文件格式错误，无法解析'); return; }
        if (!data || !data._dgPresetExport) { toast('error', '不是有效的副本生成器预设文件'); return; }

        // 为同名预设生成唯一名称（加数字后缀直到不重复）
        function uniqueName(name, existing) {
          if (!existing.find(x => x.name === name)) return { name, renamed: false };
          let n = 2;
          while (existing.find(x => x.name === `${name} (${n})`)) n++;
          return { name: `${name} (${n})`, renamed: true, original: name };
        }

        // 为每条预设分配最终名称（不改变原始数据，只生成导入副本）
        const resolveGroup = (incoming, existing) =>
          (incoming || []).map(pr => {
            const { name, renamed, original } = uniqueName(pr.name, existing);
            return { preset: { ...pr, name }, renamed, original: renamed ? original : null };
          });

        const resolvedGen    = resolveGroup(data.genPresets,    savedGenPresets);
        const resolvedInj    = resolveGroup(data.injPresets,    savedInjectionPresets);
        const resolvedPrompt = resolveGroup(data.promptPresets, savedPromptPresets);
        const allResolved    = [...resolvedGen, ...resolvedInj, ...resolvedPrompt];

        if (!allResolved.length) { toast('warning', '文件中没有可识别的预设数据'); return; }

        // 构建预览列表
        const makeRows = (resolved, label) => resolved.map(({ preset, renamed, original }) => {
          const nameHtml = renamed
            ? `${esc(preset.name)} <span style="color:var(--text3);font-size:11px;">（原名：${esc(original)}）</span>`
            : esc(preset.name);
          return `<div style="padding:4px 0;border-bottom:1px solid var(--border);">[${label}] ${nameHtml}</div>`;
        }).join('');

        const bodyHtml =
          `<div style="font-size:12px;color:var(--text2);margin-bottom:8px;">以下 <b style="color:var(--accent2);">${allResolved.length}</b> 个预设将被导入（同名自动加后缀）：</div>
           <div style="max-height:220px;overflow-y:auto;">
             ${makeRows(resolvedGen, '生成器')}
             ${makeRows(resolvedInj, '注入')}
             ${makeRows(resolvedPrompt, '提示词')}
           </div>`;

        showModal({
          title: '确认导入',
          body: bodyHtml,
          footer: `<button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-import-confirm">确认导入</button>`
                + `<button class="dg-btn" id="dg-import-cancel" style="padding:8px 18px;">取消</button>`,
          onAfterRender: () => {
            $p.find('#dg-import-confirm').on('click', () => {
              savedGenPresets.push(   ...resolvedGen.map(r    => r.preset));
              savedInjectionPresets.push(...resolvedInj.map(r => r.preset));
              savedPromptPresets.push(...resolvedPrompt.map(r => r.preset));
              try { localStorage.setItem(STORAGE_KEY_GEN_PRESETS,        JSON.stringify(savedGenPresets));        } catch(e) {}
              try { localStorage.setItem(STORAGE_KEY_INJECTION_PRESETS,  JSON.stringify(savedInjectionPresets));  } catch(e) {}
              try { localStorage.setItem(STORAGE_KEY_PROMPT_PRESETS,     JSON.stringify(savedPromptPresets));     } catch(e) {}
              renderGenPresets(); renderInjectionPresets(); renderPromptPresets();
              const renamedCount = allResolved.filter(r => r.renamed).length;
              closeModal();
              toast('success', `已导入 ${allResolved.length} 个预设${renamedCount ? `，${renamedCount} 个同名已加后缀` : ''}`);
            });
            $p.find('#dg-import-cancel').on('click', closeModal);
          },
        });
      };
      reader.readAsText(file);
    });
  }

  function switchView(v) {
    const $p = getPopup(); if (!$p) return;
    $p.find('.dg-view').removeClass('active');
    $p.find(`#dg-view-${v}`).addClass('active');
    $p.find('.dg-nav-btn').removeClass('active');
    $p.find(`#dg-nav-${v==='generator'?'gen':'set'}`).addClass('active');
  }

  function setTheme(t) {
    currentTheme = t;
    const $p = getPopup();
    if ($p) {
      // 主题通过 CSS class 和 CSS 变量生效，shell 使用固定遮罩颜色不受影响
      $p.removeClass('dg-dark dg-light dg-cyber dg-guofeng').addClass(`dg-${t}`);
