      onAfterRender: () => {
        // 计算并显示 token 估算
        // CJK 字符各约 1 token；ASCII 按空白分词后约 1 token/词
        (function() {
          const txt = builtPrompt || '';
          const cjk = (txt.match(/[\u3000-\u9fff\uac00-\ud7af\uf900-\ufaff]/g) || []).length;
          const ascii = (txt.replace(/[\u3000-\u9fff\uac00-\ud7af\uf900-\ufaff]/g, ' ')
                           .match(/[a-zA-Z0-9_\-\.]+/g) || []).length;
          const est = cjk + ascii;
          $p.find('#dg-token-count').text(`≈ ${est.toLocaleString()} tokens`);
        })();
        $p.find('#dg-preview-prompt-toggle').on('click', function () {
          const $box = $p.find('#dg-preview-prompt-box');
          $box.toggle();
          $j(this).text($box.is(':visible') ? '▾ 收起完整发送Prompt' : '▸ 展开完整发送Prompt');
