        $p.find('#dg-cancel-gen').on('click', closeModal);
      },
    });
  }

  async function runGeneration(cfg, prebuiltPrompt) {
    isGenerating = true;
    const $p = getPopup();
    if ($p) $p.find('#dg-generate-btn').prop('disabled', true).text('生成中...');

    showModal({
      title: '正在同步深渊信号...',
      body: `<div class="dg-loading" style="justify-content:center;padding:28px 0;">
               <div class="dg-spinner"></div><span>DUNGEON INITIALIZING...</span>
             </div>
             <div class="dg-info-card" id="dg-gen-status">请等待世界重构...</div>`,
      footer: '', closable: false,
    });

    try {
      const prompt = prebuiltPrompt || await buildPrompt(cfg);
      log('Prompt length:', prompt.length);
      const aiText = await callAI(prompt);
      log('Response length:', aiText.length);

      const parsed = parseResponse(aiText);

      let pName   = cfg.name || '副本';
      let pRating = (cfg.ratings.includes('全选') || !cfg.ratings.length) ? '?' : cfg.ratings[0];
      if (parsed.info) {
        const info = parseDungeonInfo(parsed.info);
        if (info.name)   pName   = info.name;
        if (info.rating) pRating = info.rating;
      }
      lastGenerated = { info: parsed.info, full: parsed.full, raw: parsed.raw, name: pName, rating: pRating };

      closeModal();
      showResultModal(parsed, pName, pRating);
    } catch(e) {
      err('Generation failed:', e);
      closeModal();
      toast('error', `生成失败: ${e.message}`, { timeOut: 6000 });
    } finally {
      isGenerating = false;
      if ($p) $p.find('#dg-generate-btn').prop('disabled', false).text('生成世界 · INITIALIZE WORLD');
    }
  }

