  // ─────────────────────────────────────────
  // 通用模态
  // ─────────────────────────────────────────
  function showModal({ title, body, footer, closable=true, onAfterRender }) {
    const $p = getPopup(); if (!$p) return;
    closeModal();

    // Android WebView: position:fixed 在 overflow:auto 内退化为 absolute，
    // 用 scrollTop + viewH 精准对齐当前可视区域，锁住 shell 防止漂移
    const H$   = getHostJQ() || $j;
    const hd   = getHostDocument();
    const hw   = getHostWindow();
    const $sh  = H$(`#${SHELL_ID}`, hd);
    const scrollTop = $sh.scrollTop() || 0;
    const viewH     = (hw.visualViewport && hw.visualViewport.height) || hw.innerHeight || 600;

    const $o = $j(`
      <div class="dg-modal-overlay" id="dg-modal-overlay">
        <div class="dg-modal">
          <div class="dg-modal-header">
            <div class="dg-modal-title">${title}</div>
            ${closable ? '<button class="dg-btn dg-btn-sm" id="dg-modal-close-x">✕</button>' : ''}
          </div>
          <div class="dg-modal-body">${body}</div>
          ${footer ? `<div class="dg-modal-footer">${footer}</div>` : ''}
        </div>
      </div>`);

    // 用 scrollTop 和视口高度覆盖 CSS 的 top:0 / height:100%
    // 使 modal 精准对齐当前可视区域（无论 shell 已滚动多少）
    $o.css({ top: scrollTop + 'px', height: viewH + 'px', bottom: 'auto' });

    // 锁住 shell 滚动，防止 modal 打开后位置漂移
    $sh.css('overflow-y', 'hidden');

    $p.append($o);
    if (closable) {
      $o.on('click', e => { if ($j(e.target).is($o)) closeModal(); });
      $p.find('#dg-modal-close-x').on('click', closeModal);
    }
    if (onAfterRender) onAfterRender();
  }
  function closeModal() {
    const $p = getPopup();
    if (!$p) return;
    $p.find('#dg-modal-overlay').remove();
    // 还原 shell 滚动（锁定期间 scrollTop 不变，用户感知不到位置跳动）
    const H$ = getHostJQ() || $j;
    const hd = getHostDocument();
    H$(`#${SHELL_ID}`, hd).css('overflow-y', '');
  }

