  }

  function loadInjectionPreset(pr) {
    const $p = getPopup(); if (!$p || !pr) return;
    $p.find('#chk-persona').prop('checked', !!pr.chkPersona);
    $p.find('#chk-char-desc').prop('checked', !!pr.chkCharDesc);
    $p.find('#dg-inject-chat').prop('checked', !!pr.injectChat);

    // 恢复 persona 文本
    if (pr.personaText !== undefined) {
      customPersonaText = pr.personaText;
      try { localStorage.setItem(STORAGE_KEY_PERSONA, customPersonaText); } catch(e) {}
      const hasNow = customPersonaText && customPersonaText.trim();
      $p.find('#dg-edit-persona-btn')
        .text(hasNow ? '✎ 已编辑' : '✎ 编辑')
        .css(hasNow ? { background:'var(--accent)', borderColor:'var(--accent2)', color:'#fff' } : { background:'', borderColor:'', color:'' });
    }

    // 恢复世界书条目选中（先清空，再重建标签并标为 active）
    if (pr.lorebookEntries && pr.lorebookEntries.length) {
      const $list = $p.find('#dg-lorebook-list');
      $list.empty();
      pr.lorebookEntries.forEach(entry => {
        const $tag = $j(`<button class="dg-tag-btn active" title="${esc((entry.content||'').slice(0,120))}">${esc(entry.label)}</button>`);
        $tag.on('click', function() { $j(this).toggleClass('active'); });
        $tag.data('entry', entry);
        $list.append($tag);
      });
    }

    toast('success', `注入预设 "${pr.name}" 已载入`);
  }

  // ─────────────────────────────────────────
  // 提示词预设
  // ─────────────────────────────────────────
  function savePromptPreset() {
    const $p = getPopup(); if (!$p) return;
    const name = $p.find('#dg-prompt-preset-name').val().trim();
    if (!name) { toast('warning','请输入预设名称'); return; }
    const content = $p.find('#dg-prompt-editor').val();
    savedPromptPresets = savedPromptPresets.filter(p=>p.name!==name);
    savedPromptPresets.unshift({ name, content, savedAt: Date.now() });
    try { localStorage.setItem(STORAGE_KEY_PROMPT_PRESETS, JSON.stringify(savedPromptPresets)); } catch(e) {}
    $p.find('#dg-prompt-preset-name').val('');
    renderPromptPresets();
    toast('success', `提示词预设 "${name}" 已保存`);
  }

  function renderPromptPresets() {
    const $p = getPopup(); if (!$p) return;
    const $sel = $p.find('#dg-prompt-preset-select');
    const prev = $sel.val();
    $sel.empty().append('<option value="">— 选择提示词预设 —</option>');
    savedPromptPresets.forEach((pr, idx) => {
      $sel.append($j('<option>').val(idx).text(pr.name));
    });
    if (prev !== '' && savedPromptPresets[parseInt(prev)]) $sel.val(prev);
  }

  function loadPromptPreset(pr) {
    const $p = getPopup(); if (!$p || !pr) return;
    currentPrompt = pr.content || DEFAULT_PROMPT;
    $p.find('#dg-prompt-editor').val(currentPrompt);
    try { localStorage.setItem(STORAGE_KEY_PROMPT, currentPrompt); } catch(e) {}
    toast('success', `提示词预设 "${pr.name}" 已载入`);
  }

  // ─────────────────────────────────────────
  // 生成器预设（保存主页全部选项）
  // ─────────────────────────────────────────
  function saveGenPreset() {
    const $p = getPopup(); if (!$p) return;
    const name = $p.find('#dg-gen-preset-name').val().trim();
    if (!name) { toast('warning', '请输入预设名称'); return; }
    const cfg = getConfig(); if (!cfg) return;
    const tagCfg = {
      customThemes:        [...customThemes],
      deletedDefaultThemes: [...deletedDefaultThemes],
      customRatings:        [...customRatings],
      deletedDefaultRatings: [...deletedDefaultRatings],
    };
    savedGenPresets = savedGenPresets.filter(p => p.name !== name);
    savedGenPresets.unshift({ name, cfg, tagCfg, savedAt: Date.now() });
    try { localStorage.setItem(STORAGE_KEY_GEN_PRESETS, JSON.stringify(savedGenPresets)); } catch(e) {}
    $p.find('#dg-gen-preset-name').val('');
    renderGenPresets();
    toast('success', `预设 "${name}" 已保存`);
  }

  function renderGenPresets() {
    const $p = getPopup(); if (!$p) return;
    const $sel = $p.find('#dg-gen-preset-select');
    const prev = $sel.val();
    $sel.empty().append('<option value="">— 选择预设 —</option>');
    savedGenPresets.forEach((pr, idx) => $sel.append($j('<option>').val(idx).text(pr.name)));
    if (prev !== '' && savedGenPresets[parseInt(prev)]) $sel.val(prev);
  }

  function loadGenPreset(pr) {
    const $p = getPopup(); if (!$p || !pr || !pr.cfg) return;
    const cfg = pr.cfg;
    $p.find('#dg-name').val(cfg.name || '');
    $p.find('#dg-players').val(cfg.players || '');
    $p.find('#dg-special').val(cfg.special || '');
    $p.find('#dg-themes-container .dg-tag-btn').removeClass('active');
    (cfg.themes || []).forEach(t => $p.find(`#dg-themes-container .dg-tag-btn[data-theme="${t}"]`).addClass('active'));
    $p.find('#dg-ratings-container .dg-rating-btn').removeClass('active');
    (cfg.ratings || []).forEach(r => $p.find(`#dg-ratings-container .dg-rating-btn[data-rating="${r}"]`).addClass('active'));
    const so = (gid, val) => {
      $p.find(`#${gid} .dg-opt-btn`).removeClass('active');
      $p.find(`#${gid} .dg-opt-btn[data-val="${val}"]`).addClass('active');
    };
    so('dg-mode-group',     cfg.mode);
    so('dg-teammate-group', cfg.teammates);
    so('dg-lang-group',     cfg.lang);
    so('dg-context-group',  cfg.readContext);
    $p.find('#dg-context-extra').toggle(cfg.readContext === '是');
    if (cfg.injectChat !== undefined) $p.find('#dg-inject-chat').prop('checked', cfg.injectChat);
    // 恢复用户特殊设定
    if (cfg.userSpecialEnabled !== undefined) {
      $p.find('#dg-user-special-chk').prop('checked', !!cfg.userSpecialEnabled);
      $p.find('#dg-user-special-extra').toggle(!!cfg.userSpecialEnabled);
      if (cfg.userSpecialEnabled) {
        const presetIds = ['副本NPC', 'Boss', '系统'];
        const isPreset  = presetIds.includes(cfg.userIdentity);
        so('dg-user-identity-group', isPreset ? cfg.userIdentity : '其他');
        $p.find('#dg-user-identity-other-wrap').toggle(!isPreset);
        $p.find('#dg-user-identity-other').val(isPreset ? '' : (cfg.userIdentity || ''));
        $p.find('#dg-user-identity-desc').val(cfg.userIdentityDesc || '');
      }
    }
    // 恢复标签配置（若预设包含）
    if (pr.tagCfg) {
      customThemes          = pr.tagCfg.customThemes         || [];
      deletedDefaultThemes  = pr.tagCfg.deletedDefaultThemes || [];
      customRatings         = pr.tagCfg.customRatings        || [];
      deletedDefaultRatings = pr.tagCfg.deletedDefaultRatings|| [];
      // 立即保存到 localStorage（和其他预设行为一致）
      try { localStorage.setItem(STORAGE_KEY_CUSTOM_THEMES,   JSON.stringify(customThemes));          } catch(e) {}
      try { localStorage.setItem(STORAGE_KEY_DELETED_THEMES,  JSON.stringify(deletedDefaultThemes));  } catch(e) {}
      try { localStorage.setItem(STORAGE_KEY_CUSTOM_RATINGS,  JSON.stringify(customRatings));         } catch(e) {}
      try { localStorage.setItem(STORAGE_KEY_DELETED_RATINGS, JSON.stringify(deletedDefaultRatings)); } catch(e) {}
      renderTagSection('theme');
      renderTagSection('rating');
    }
    toast('success', `预设 "${pr.name}" 已载入`);
  }

  // ─────────────────────────────────────────
  // 世界书条目加载
  // ─────────────────────────────────────────
  async function loadLorebookEntries() {
    const $p = getPopup(); if (!$p) return;
    const $list = $p.find('#dg-lorebook-list');
    $list.html('<span class="dg-hint" style="padding:8px;">正在读取当前挂载的条目...</span>');
    try {
      const entries = await getActiveWorldbookEntries();
      $list.empty();
      if (!entries.length) { $list.html('<span class="dg-hint" style="padding:8px;">当前未发现挂载的世界书条目</span>'); return; }
      entries.forEach(entry => {
        const $tag = $j(`<button class="dg-tag-btn" title="${esc((entry.content||'').slice(0,120))}">${esc(entry.label)}</button>`);
        $tag.on('click', function () { $j(this).toggleClass('active'); });
        $tag.data('entry', entry);
        $list.append($tag);
      });
      toast('success', `已载入 ${entries.length} 个挂载条目`);
    } catch(e) {
      err('loadLorebookEntries:', e);
      $list.html('<span class="dg-hint" style="padding:8px;color:var(--accent2);">加载失败</span>');
    }
  }

  // ─────────────────────────────────────────
  // 初始化
  // ─────────────────────────────────────────
  let initAttempts = 0;
  async function init() {
    initAttempts++;
    log(`Init attempt ${initAttempts}`);

    if (loadApis()) {
      // jQuery 已就绪，直接启动 UI（世界书 API 就绪状态由 apisReady 单独追踪）
      log(`jQuery OK, apisReady=${apisReady}, starting UI...`);
      loadSettings();
      addMenuItem();
      _createShellDOM(); // 常驻 DOM：一次性创建，后续打开只切换 display
    } else if (initAttempts < 25) {
      const delay = initAttempts <= 5 ? 1000 : initAttempts <= 15 ? 2000 : 3000;
      log(`jQuery 未就绪，${delay}ms 后重试...`);
      setTimeout(init, delay);
    } else {
      err('达到最大重试次数，仍未检测到 jQuery，放弃初始化。');
    }
  }

  // ─────────────────────────────────────────
  // 启动
  // ─────────────────────────────────────────
  const FLAG = `${SCRIPT_ID}_Loaded_v2_0_2`;
  if (typeof window[FLAG] === 'undefined') {
    window[FLAG] = true;

    const wjq = setInterval(() => {
      $j = typeof $ !== 'undefined' ? $ : (typeof jQuery !== 'undefined' ? jQuery : null);
      if ($j) {
        clearInterval(wjq);
        if (typeof toastr !== 'undefined') toastr_api = toastr;

        const state = document.readyState;
        const startDelay = state === 'complete' ? 1500 : 4000;
        log(`document.readyState=${state}，将在 ${startDelay}ms 后启动`);

        const go = () => setTimeout(init, startDelay);
        if (state === 'complete' || state === 'interactive') go();
        else document.addEventListener('DOMContentLoaded', go);
      }
    }, 100);
  } else {
    warn('Script already loaded, skipping.');
  }

})();
